PACKAGE_IMAGE_ARCHIVE_CANDIDATE_NAMES = (
    "novali-v7-standalone.tar",
    "novali-v6-standalone.tar",
)
DIST_PACKAGE_NAME_PATTERN = re.compile(
    r"novali-v(?P<major>\d+)_rc(?P<release>\d+)(?:_(?P<patch>\d+))?-standalone"
)


def _preferred_package_image_archive(package_root: Path) -> Path:
    image_root = package_root / "image"
    for name in PACKAGE_IMAGE_ARCHIVE_CANDIDATE_NAMES:
        candidate = image_root / name
        if candidate.exists():
            return candidate
    return image_root / PACKAGE_IMAGE_ARCHIVE_CANDIDATE_NAMES[0]


def _versioned_dist_package_sort_key(name: str) -> tuple[int, int, int] | None:
    match = DIST_PACKAGE_NAME_PATTERN.fullmatch(name)
    if not match:
        return None
    return (
        int(match.group("major")),
        int(match.group("release")),
        int(match.group("patch") or 0),
    )


