def _now() -> str:
    return datetime.now(timezone.utc).isoformat()


def _json_dump(payload: Any) -> str:
    return json.dumps(payload, indent=2, sort_keys=True)


def _write_json_file(path: str | Path, payload: Any) -> None:
    target = Path(path)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(_json_dump(payload), encoding="utf-8")


def _normalize_path(value: Any) -> str:
    if value in {None, ""}:
        return ""
    try:
        return str(Path(str(value)).resolve())
    except OSError:
        return str(value)


def _remap_packaged_path_for_root(path: str, package_root: str | Path) -> str:
    normalized = str(path or "").strip()
    if not normalized:
        return ""
    candidate = Path(normalized)
    try:
        if candidate.exists():
            return str(candidate)
    except OSError:
        pass

    current_package_root = Path(package_root).resolve()
    normalized_parts = [part for part in normalized.replace("\\", "/").split("/") if part]
    candidate_suffixes: list[list[str]] = []
    package_anchor = current_package_root.name
    if package_anchor in normalized_parts:
        package_suffix = normalized_parts[normalized_parts.index(package_anchor) + 1 :]
        candidate_suffixes.append(package_suffix)

    for content_anchor in (
        "operator_state",
        "runtime_data",
        "novali-active_workspace",
        "directive_inputs",
        "directives",
        "manual_acceptance_samples",
        "trusted_sources",
        "docs",
        "samples",
        "image",
        "launch",
        "data",
        "logs",
    ):
        if content_anchor in normalized_parts:
            candidate_suffixes.append(normalized_parts[normalized_parts.index(content_anchor) :])

    for suffix in candidate_suffixes:
        remapped = current_package_root.joinpath(*suffix) if suffix else current_package_root
        if remapped.exists():
            return str(remapped)
    return normalized


def _normalize_endpoint_base(value: Any) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    parsed = urllib.parse.urlsplit(text)
    if parsed.scheme not in {"http", "https"} or not parsed.netloc:
        return text
    normalized_path = parsed.path.rstrip("/") or ""
    return urllib.parse.urlunsplit((parsed.scheme, parsed.netloc, normalized_path, "", ""))


def _external_provider_validation_response_schema() -> dict[str, Any]:
    return {
        "type": "object",
        "properties": {
            "provider_ready": {"type": "boolean"},
            "provider_family": {"type": "string"},
            "recommended_model": {"type": "string"},
            "transport_notes": {
                "type": "array",
                "items": {"type": "string"},
                "minItems": 2,
            },
            "governance_note": {"type": "string"},
        },
        "required": [
            "provider_ready",
            "provider_family",
            "recommended_model",
            "transport_notes",
            "governance_note",
        ],
        "additionalProperties": False,
    }


def _slug(value: str, *, fallback: str) -> str:
    token = re.sub(r"[^A-Za-z0-9._-]+", "_", str(value or "").strip()).strip("._-")
    return token or fallback


def _is_under_path(candidate: str | Path, root: str | Path) -> bool:
    try:
        Path(str(candidate)).resolve().relative_to(Path(str(root)).resolve())
        return True
    except ValueError:
        return False


def _read_json_file(path: str | Path | None) -> dict[str, Any]:
    if not path:
        return {}
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        return {}


def _directive_id_from_wrapper(path: str | Path | None) -> str:
    payload = _read_json_file(path)
    return str(dict(payload.get("directive_spec", {})).get("directive_id", "")).strip()


def _read_jsonl_file(path: str | Path | None) -> list[dict[str, Any]]:
    if not path:
        return []
    try:
        rows: list[dict[str, Any]] = []
        for line in Path(path).read_text(encoding="utf-8").splitlines():
            line = str(line).strip()
            if not line:
                continue
            try:
                payload = json.loads(line)
            except json.JSONDecodeError:
                continue
            if isinstance(payload, dict):
                rows.append(payload)
        return rows
    except OSError:
        return []


def _read_workspace_runtime_events(
    primary_path: str | Path | None,
    *,
    workspace_id: str = "",
    session_id: str = "",
    directive_id: str = "",
) -> list[dict[str, Any]]:
    candidate_paths: list[Path] = []
    seen_paths: set[str] = set()
    primary = Path(primary_path).resolve() if primary_path else None
    if primary is not None and primary.exists():
        seen_paths.add(str(primary))
        candidate_paths.append(primary)
        if primary.parent.exists():
            for item in sorted(primary.parent.glob("*.jsonl")):
                resolved = item.resolve()
                if str(resolved) in seen_paths:
                    continue
                seen_paths.add(str(resolved))
                candidate_paths.append(resolved)

    rows: list[dict[str, Any]] = []
    seen_rows: set[str] = set()
    for path in candidate_paths:
        for payload in _read_jsonl_file(path):
            payload_workspace_id = str(payload.get("workspace_id", "")).strip()
            payload_session_id = str(payload.get("session_id", "")).strip()
            payload_directive_id = str(payload.get("directive_id", "")).strip()
            keep = False
            if workspace_id and payload_workspace_id == workspace_id:
                keep = True
            elif session_id and payload_session_id == session_id:
                keep = True
            elif directive_id and payload_directive_id == directive_id and payload_workspace_id == workspace_id:
                keep = True
            elif not workspace_id and not session_id and not directive_id:
                keep = True
            if not keep:
                continue
            row_key = json.dumps(payload, sort_keys=True)
            if row_key in seen_rows:
                continue
            seen_rows.add(row_key)
            rows.append(payload)
    rows.sort(
        key=lambda item: (
            str(item.get("timestamp", "")),
            str(item.get("session_id", "")),
            str(item.get("event_type", "")),
        )
    )
    return rows


def _format_bytes(size_bytes: int | float | None) -> str:
    if size_bytes in {None, ""}:
        return ""
    value = float(size_bytes)
    units = ["B", "KB", "MB", "GB"]
    unit = units[0]
    for unit in units:
        if value < 1024.0 or unit == units[-1]:
            break
        value /= 1024.0
    return f"{value:.1f} {unit}" if unit != "B" else f"{int(value)} {unit}"


def _format_timestamp(value: Any) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    try:
        return datetime.fromisoformat(text.replace("Z", "+00:00")).astimezone().strftime("%Y-%m-%d %H:%M:%S %Z")
    except ValueError:
        return text


def _parse_timestamp(value: Any) -> datetime | None:
    text = str(value or "").strip()
    if not text:
        return None
    try:
        return datetime.fromisoformat(text.replace("Z", "+00:00"))
    except ValueError:
        return None


def _stable_hash_payload(payload: Any) -> str:
    return hashlib.sha256(
        json.dumps(payload, sort_keys=True).encode("utf-8")
    ).hexdigest()


