def _child_role_label(role: str) -> str:
    normalized = str(role or "").strip().lower()
    return {
        "librarian": "Librarian",
        "verifier": "Verifier",
    }.get(normalized, "Child")


def _recommendation_governance_tone(posture: str) -> str:
    normalized = str(posture or "").strip().lower()
    if normalized in {"operator_override", "operator_hold", "operator_defer"}:
        return "warning"
    if normalized in {"follow_recommendation", "stable_recent_support"}:
        return "success"
    return "info"


def _recommendation_audit_tracking_label(state: str) -> str:
    normalized = str(state or "").strip().lower()
    mapping = {
        "recommendation_followed": "Recommendation followed",
        "recommendation_on_hold": "Recommendation on hold",
        "recommendation_deferred": "Recommendation deferred",
        "operator_overridden": "Operator overridden",
        "pending_operator_choice": "Pending operator choice",
        "no_strong_recommendation_active": "No strong recommendation active",
    }
    if normalized in mapping:
        return mapping[normalized]
    if normalized:
        return normalized.replace("_", " ")
    return "<none>"


def _recommendation_audit_tracking_tone(state: str) -> str:
    normalized = str(state or "").strip().lower()
    if normalized == "recommendation_followed":
        return "success"
    if normalized in {
        "recommendation_on_hold",
        "recommendation_deferred",
        "operator_overridden",
        "no_strong_recommendation_active",
    }:
        return "warning"
    return "info"


def _intervention_audit_tone(state: str) -> str:
    normalized = str(state or "").strip().lower()
    if normalized in {
        "followed_and_supported",
        "override_supported",
        "hold_was_prudent",
        "defer_was_prudent",
        "no_strong_recommendation_prudent",
    }:
        return "success"
    if normalized in {
        "followed_but_weak",
        "override_not_supported",
        "unnecessary_override",
        "missed_action",
        "unresolved",
    }:
        return "warning"
    return "info"


def _intervention_calibration_tone(posture: str) -> str:
    normalized = str(posture or "").strip().lower()
    if normalized == "stabilizing":
        return "success"
    if normalized in {"mixed", "unclear", "thin"}:
        return "warning"
    return "info"


def _intervention_prudence_tone(posture: str) -> str:
    normalized = str(posture or "").strip().lower()
    if normalized in {"supported_recently", "caution_prudent"}:
        return "success"
    if normalized in {"mixed_recent_history", "thin_history", "unresolved_recent_history"}:
        return "warning"
    return "info"


def _recommendation_trust_signal_tone(state: str) -> str:
    normalized = str(state or "").strip().lower()
    if normalized in {"supported", "recently_stable"}:
        return "success"
    if normalized in {"mixed", "thin", "unclear", "recently_unstable"}:
        return "warning"
    return "info"


def _governance_summary_tone(classification: str) -> str:
    normalized = str(classification or "").strip().lower()
    if normalized in {"supported", "recently_stable"}:
        return "success"
    if normalized in {
        "cautious",
        "mixed",
        "thin",
        "unresolved",
        "recently_unstable",
    }:
        return "warning"
    return "info"


def _governance_trend_tone(state: str) -> str:
    normalized = str(state or "").strip().lower()
    if normalized in {"strengthening", "stabilizing", "drifting_supportive"}:
        return "success"
    if normalized in {
        "weakening",
        "mixed",
        "oscillating",
        "drifting_cautious",
        "unresolved",
    }:
        return "warning"
    return "info"


def _operator_guidance_tone(state: str) -> str:
    normalized = str(state or "").strip().lower()
    if normalized in {"follow_recommendation", "continue_current_posture"}:
        return "success"
    if normalized in {
        "hold",
        "defer",
        "review_required",
        "maintain_no_strong_recommendation",
        "await_more_evidence",
        "cautious",
        "mixed",
        "thin",
        "unresolved",
    }:
        return "warning"
    return "info"


def _action_readiness_tone(state: str) -> str:
    normalized = str(state or "").strip().lower()
    if normalized in {"ready_now", "maintain_current_posture"}:
        return "success"
    if normalized in {
        "not_ready",
        "blocked",
        "awaiting_review",
        "awaiting_more_evidence",
    }:
        return "warning"
    return "info"


def _guided_handoff_tone(destination: str) -> str:
    normalized = str(destination or "").strip().lower()
    if normalized in {"home", "observability"}:
        return "info"
    if normalized in {"review", "workspace"}:
        return "warning"
    if normalized == "continue_current_posture":
        return "success"
    return "info"


def _operator_flow_tone(state: str) -> str:
    normalized = str(state or "").strip().lower()
    if normalized in {"ready_to_act", "maintaining_current_posture"}:
        return "success"
    if normalized in {
        "waiting_on_review",
        "waiting_on_evidence",
        "blocked",
        "navigating_to_next_surface",
        "mixed",
    }:
        return "warning"
    return "info"


def _demo_readiness_tone(state: str) -> str:
    normalized = str(state or "").strip().lower()
    if normalized == "clear":
        return "success"
    if normalized in {"mostly_clear", "mixed", "needs_operator_clarity"}:
        return "warning"
    return "info"


def _demo_run_readiness_tone(state: str) -> str:
    normalized = str(state or "").strip().lower()
    if normalized in {"ready_to_run", "maintain_current_posture"}:
        return "success"
    if normalized in {
        "awaiting_review",
        "awaiting_more_evidence",
        "not_ready",
        "blocked",
        "mixed",
    }:
        return "warning"
    return "info"


def _demo_execution_tone(state: str) -> str:
    normalized = str(state or "").strip().lower()
    if normalized == "completed_bounded":
        return "success"
    if normalized in {
        "partial_outputs_available",
        "awaiting_review",
        "awaiting_more_evidence",
        "blocked",
    }:
        return "warning"
    return "info"


def _demo_output_completion_tone(state: str) -> str:
    normalized = str(state or "").strip().lower()
    if normalized in {"reviewable_outputs_available", "completed_bounded"}:
        return "success"
    if normalized in {
        "partial_outputs_available",
        "awaiting_review",
        "awaiting_more_evidence",
        "blocked",
        "no_outputs_yet",
    }:
        return "warning"
    return "info"


def _build_action_readiness_display(
    readiness_payload: Mapping[str, Any],
    guided_handoff_payload: Mapping[str, Any],
    readiness_history_payload: Mapping[str, Any],
) -> dict[str, str]:
    blocker_count = int(readiness_payload.get("blocker_count", 0) or 0)
    prerequisite_count = int(readiness_payload.get("prerequisite_count", 0) or 0)
    satisfied_prerequisite_count = int(
        readiness_payload.get("satisfied_prerequisite_count", 0) or 0
    )
    missing_evidence_count = int(
        readiness_payload.get("missing_evidence_count", 0) or 0
    )
    readiness_state = str(readiness_payload.get("action_readiness_state", "") or "")
    readiness_label = str(
        readiness_payload.get("action_readiness_label", "")
        or readiness_state
        or "<none>"
    )
    readiness_detail = str(
        readiness_payload.get("action_readiness_summary", "")
        or readiness_payload.get("reason_summary", "")
        or "No action-readiness summary is recorded."
    )
    blocker_label = (
        str(readiness_payload.get("top_blocker_label", "") or "").strip()
        if blocker_count
        else "No blockers recorded"
    ) or f"{blocker_count} blocker(s)"
    blocker_detail = str(
        readiness_payload.get("blocker_summary", "")
        or readiness_payload.get("top_blocker_reason", "")
        or "No blockers are currently recorded."
    )
    prerequisite_label = (
        f"{satisfied_prerequisite_count}/{prerequisite_count} satisfied"
        if prerequisite_count
        else "No prerequisites recorded"
    )
    prerequisite_detail = str(
        readiness_payload.get("prerequisite_summary", "")
        or "No prerequisite summary is recorded."
    )
    missing_evidence_label = (
        f"{missing_evidence_count} evidence gap(s)"
        if missing_evidence_count
        else "No missing evidence"
    )
    missing_evidence_detail = str(
        readiness_payload.get("missing_evidence_summary", "")
        or "No missing-evidence summary is recorded."
    )
    guided_handoff_label = str(
        guided_handoff_payload.get("guided_next_destination_label", "")
        or guided_handoff_payload.get("guided_next_destination", "")
        or "<none>"
    )
    guided_handoff_detail = str(
        guided_handoff_payload.get("guided_handoff_summary", "")
        or guided_handoff_payload.get("reason_summary", "")
        or "No guided handoff summary is recorded."
    )
    readiness_history_label = str(
        readiness_history_payload.get("entry_count", 0) or 0
    )
    readiness_history_detail = (
        f"latest={readiness_label} | "
        f"destination={guided_handoff_label}"
    )
    return {
        "action_readiness_state": readiness_state or "<none>",
        "action_readiness_label": readiness_label,
        "action_readiness_detail": readiness_detail,
        "action_readiness_blocker_label": blocker_label,
        "action_readiness_blocker_detail": blocker_detail,
        "action_readiness_prerequisite_label": prerequisite_label,
        "action_readiness_prerequisite_detail": prerequisite_detail,
        "action_readiness_missing_evidence_label": missing_evidence_label,
        "action_readiness_missing_evidence_detail": missing_evidence_detail,
        "guided_handoff_destination": str(
            guided_handoff_payload.get("guided_next_destination", "") or "<none>"
        ),
        "guided_handoff_label": guided_handoff_label,
        "guided_handoff_detail": guided_handoff_detail,
        "action_readiness_history_label": readiness_history_label,
        "action_readiness_history_detail": readiness_history_detail,
    }


def _build_demo_scenario_display(
    demo_scenario_payload: Mapping[str, Any],
    demo_run_readiness_payload: Mapping[str, Any],
    demo_operator_walkthrough_payload: Mapping[str, Any],
    demo_success_rubric_payload: Mapping[str, Any],
    demo_scenario_history_payload: Mapping[str, Any],
) -> dict[str, str]:
    scenario_name = str(
        demo_scenario_payload.get("scenario_name", "")
        or demo_scenario_payload.get("scenario_id", "")
        or "<none>"
    )
    scenario_purpose = str(
        demo_scenario_payload.get("scenario_purpose", "")
        or "No demo-scenario purpose is recorded."
    )
    demo_run_readiness_state = str(
        demo_run_readiness_payload.get("demo_run_readiness_state", "")
        or "<none>"
    )
    demo_run_readiness_label = str(
        demo_run_readiness_payload.get("demo_run_readiness_label", "")
        or demo_run_readiness_state
        or "<none>"
    )
    demo_run_readiness_detail = str(
        demo_run_readiness_payload.get("demo_run_readiness_summary", "")
        or demo_run_readiness_payload.get("reason_summary", "")
        or "No demo-run readiness summary is recorded."
    )
    current_demo_step_label = str(
        demo_operator_walkthrough_payload.get("current_walkthrough_step_label", "")
        or demo_operator_walkthrough_payload.get("what_to_do_first", "")
        or "<none>"
    )
    current_demo_step_detail = str(
        demo_operator_walkthrough_payload.get("current_walkthrough_step_detail", "")
        or demo_operator_walkthrough_payload.get("what_to_do_first", "")
        or "No current demo step is recorded."
    )
    next_demo_step_label = str(
        demo_operator_walkthrough_payload.get("next_walkthrough_step_label", "")
        or demo_operator_walkthrough_payload.get("what_to_do_next", "")
        or "<none>"
    )
    next_demo_step_detail = str(
        demo_operator_walkthrough_payload.get("next_walkthrough_step_detail", "")
        or demo_operator_walkthrough_payload.get("what_to_do_next", "")
        or "No next demo step is recorded."
    )
    demo_success_rubric_label = str(
        demo_success_rubric_payload.get("rubric_summary_label", "")
        or f"{int(demo_success_rubric_payload.get('satisfied_count', 0) or 0)}/"
        f"{int(demo_success_rubric_payload.get('criterion_count', 0) or 0)} satisfied"
        if demo_success_rubric_payload
        else "No rubric recorded"
    )
    demo_success_rubric_detail = str(
        demo_success_rubric_payload.get("rubric_summary", "")
        or "No demo success rubric is recorded."
    )
    expected_outputs = [
        str(item.get("label", "") or item.get("path", "") or "<none>")
        for item in list(demo_scenario_payload.get("expected_artifact_outputs", []) or [])
        if isinstance(item, dict)
    ]
    expected_outputs_label = (
        f"{len(expected_outputs)} expected output(s)"
        if expected_outputs
        else "No expected outputs recorded"
    )
    expected_outputs_detail = (
        " | ".join(expected_outputs)
        if expected_outputs
        else str(
            demo_scenario_payload.get("scenario_expected_output_summary", "")
            or "No expected outputs are recorded."
        )
    )
    demo_blocker_label = (
        str(demo_run_readiness_payload.get("top_blocker_label", "") or "").strip()
        or f"{int(demo_run_readiness_payload.get('blocker_count', 0) or 0)} blocker(s)"
        if int(demo_run_readiness_payload.get("blocker_count", 0) or 0)
        else "No demo blockers recorded"
    )
    demo_blocker_detail = str(
        demo_run_readiness_payload.get("blocker_summary", "")
        or "No demo blockers are currently recorded."
    )
    demo_reset_rerun_label = str(
        demo_run_readiness_payload.get("reset_rerun_label", "")
        or "Reset / rerun"
    )
    demo_reset_rerun_detail = str(
        demo_run_readiness_payload.get("reset_rerun_summary", "")
        or "No reset or rerun guidance is recorded."
    )
    walkthrough_destination_label = str(
        demo_run_readiness_payload.get("guided_next_destination_label", "")
        or demo_operator_walkthrough_payload.get("where_to_go_next_label", "")
        or "<none>"
    )
    walkthrough_destination_detail = str(
        demo_operator_walkthrough_payload.get("where_to_go_next_detail", "")
        or demo_run_readiness_payload.get("guided_handoff_summary", "")
        or "No next-surface guidance is recorded."
    )
    demo_history_label = str(demo_scenario_history_payload.get("entry_count", 0) or 0)
    demo_history_detail = (
        f"latest={scenario_name} | readiness={demo_run_readiness_label}"
    )
    return {
        "demo_scenario_name": scenario_name,
        "demo_scenario_purpose": scenario_purpose,
        "demo_run_readiness_state": demo_run_readiness_state,
        "demo_run_readiness_label": demo_run_readiness_label,
        "demo_run_readiness_detail": demo_run_readiness_detail,
        "current_demo_step_label": current_demo_step_label,
        "current_demo_step_detail": current_demo_step_detail,
        "next_demo_step_label": next_demo_step_label,
        "next_demo_step_detail": next_demo_step_detail,
        "demo_success_rubric_label": demo_success_rubric_label,
        "demo_success_rubric_detail": demo_success_rubric_detail,
        "expected_outputs_label": expected_outputs_label,
        "expected_outputs_detail": expected_outputs_detail,
        "demo_blocker_label": demo_blocker_label,
        "demo_blocker_detail": demo_blocker_detail,
        "demo_reset_rerun_label": demo_reset_rerun_label,
        "demo_reset_rerun_detail": demo_reset_rerun_detail,
        "walkthrough_destination_label": walkthrough_destination_label,
        "walkthrough_destination_detail": walkthrough_destination_detail,
        "demo_history_label": demo_history_label,
        "demo_history_detail": demo_history_detail,
    }


def _build_trusted_demo_candidate_display(
    trusted_demo_scenario_payload: Mapping[str, Any],
    trusted_demo_directive_payload: Mapping[str, Any],
    trusted_demo_success_rubric_payload: Mapping[str, Any],
    trusted_demo_skill_target_payload: Mapping[str, Any],
    trusted_demo_selection_rationale_payload: Mapping[str, Any],
) -> dict[str, str]:
    candidate_name = str(
        trusted_demo_scenario_payload.get("scenario_name", "")
        or trusted_demo_scenario_payload.get("scenario_id", "")
        or "<none>"
    )
    candidate_purpose = str(
        trusted_demo_scenario_payload.get("scenario_purpose", "")
        or "No trusted-source demo candidate purpose is recorded."
    )
    directive_exists = bool(
        trusted_demo_directive_payload.get("directive_exists", False)
    )
    packaged_directive_exists = bool(
        trusted_demo_directive_payload.get("packaged_directive_exists", False)
    )
    directive_label = (
        "Directive ready"
        if directive_exists and packaged_directive_exists
        else "Directive partial"
        if directive_exists or packaged_directive_exists
        else "Directive missing"
    )
    directive_detail = str(
        trusted_demo_directive_payload.get("directive_summary", "")
        or trusted_demo_directive_payload.get("what_the_directive_encodes_summary", "")
        or "No trusted-source directive summary is recorded."
    )
    rubric_label = str(
        trusted_demo_success_rubric_payload.get("rubric_summary_label", "")
        or f"{int(trusted_demo_success_rubric_payload.get('satisfied_count', 0) or 0)}/"
        f"{int(trusted_demo_success_rubric_payload.get('criterion_count', 0) or 0)} satisfied"
        if trusted_demo_success_rubric_payload
        else "No rubric recorded"
    )
    rubric_detail = str(
        trusted_demo_success_rubric_payload.get("rubric_summary", "")
        or "No trusted-source success rubric is recorded."
    )
    expected_outputs = [
        str(item.get("label", "") or item.get("target_path", "") or "<none>")
        for item in list(
            trusted_demo_scenario_payload.get("expected_output_pack", []) or []
        )
        if isinstance(item, dict)
    ]
    expected_outputs_label = (
        f"{len(expected_outputs)} expected output(s)"
        if expected_outputs
        else "No trusted-source outputs recorded"
    )
    expected_outputs_detail = (
        " | ".join(expected_outputs)
        if expected_outputs
        else str(
            trusted_demo_scenario_payload.get("expected_output_summary", "")
            or "No trusted-source expected outputs are recorded."
        )
    )
    knowledge_gap_label = str(
        trusted_demo_scenario_payload.get("knowledge_gap_label", "")
        or "Knowledge gap / escalation"
    )
    knowledge_gap_detail = str(
        trusted_demo_scenario_payload.get("knowledge_gap_summary", "")
        or "No trusted-source knowledge-gap summary is recorded."
    )
    request_sources = [
        str(item)
        for item in list(
            trusted_demo_scenario_payload.get("expected_trusted_source_ids", []) or []
        )
        if str(item)
    ]
    request_shape_label = (
        f"{len(request_sources)} trusted source id(s)"
        if request_sources
        else "Trusted-source request shape"
    )
    request_shape_detail = str(
        trusted_demo_scenario_payload.get("trusted_source_request_summary", "")
        or "No trusted-source request-shape summary is recorded."
    )
    skill_target_label = str(
        trusted_demo_skill_target_payload.get("skill_target_label", "")
        or trusted_demo_skill_target_payload.get("target_kind_label", "")
        or trusted_demo_skill_target_payload.get("target_kind", "")
        or "<none>"
    )
    skill_target_detail = str(
        trusted_demo_skill_target_payload.get("skill_target_summary", "")
        or "No trusted-source skill-target summary is recorded."
    )
    rationale_label = "Why this scenario was chosen"
    rationale_detail = str(
        trusted_demo_selection_rationale_payload.get("selection_rationale_summary", "")
        or "No trusted-source selection rationale is recorded."
    )
    return {
        "candidate_name": candidate_name,
        "candidate_purpose": candidate_purpose,
        "directive_label": directive_label,
        "directive_detail": directive_detail,
        "rubric_label": rubric_label,
        "rubric_detail": rubric_detail,
        "expected_outputs_label": expected_outputs_label,
        "expected_outputs_detail": expected_outputs_detail,
        "knowledge_gap_label": knowledge_gap_label,
        "knowledge_gap_detail": knowledge_gap_detail,
        "request_shape_label": request_shape_label,
        "request_shape_detail": request_shape_detail,
        "skill_target_label": skill_target_label,
        "skill_target_detail": skill_target_detail,
        "rationale_label": rationale_label,
        "rationale_detail": rationale_detail,
    }


