def _real_work_benchmark_review_decision_template_path(package_root: Path) -> Path:
    return package_root / REAL_WORK_BENCHMARK_REVIEW_TEMPLATE_RELATIVE_PATH


def _load_json_file_if_exists(path: Path) -> dict[str, Any]:
    try:
        if not path.exists():
            return {}
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _default_real_work_benchmark_review_decision_template(
    *,
    workflow_id: str,
    workflow_name: str,
    directive_file_path: str,
) -> dict[str, Any]:
    return {
        "schema_name": REAL_WORK_BENCHMARK_REVIEW_TEMPLATE_SCHEMA_NAME,
        "schema_version": REAL_WORK_BENCHMARK_REVIEW_TEMPLATE_SCHEMA_VERSION,
        "workflow_id": workflow_id,
        "workflow_name": workflow_name,
        "directive_file_path": directive_file_path,
        "template_state": "awaiting_operator_confirmation",
        "explicit_operator_confirmation": False,
        "promotion_outcome_state": "awaiting_operator_confirmation",
        "operator_reviewer": "",
        "confirmation_recorded_at": "",
        "decision_basis_note": "",
        "allowed_outcome_states": [
            "promotion_confirmed_with_review_gate",
            "hold_confirmed_with_review_gate",
            "defer_confirmed",
            "blocked_review_outcome",
            "awaiting_operator_confirmation",
        ],
        "operator_instruction": (
            "Update this file only after a human reviewer has inspected the benchmark decision packet, promotion-readiness evidence, unresolved-bundle evidence, and output inventory."
        ),
        "non_authoritative_note": (
            "This template records operator review only. It does not authorize policy change or automatic promotion."
        ),
    }


