    def _save_real_work_benchmark_execution_views(
        self,
        *,
        operator_snapshot: dict[str, Any],
    ) -> dict[str, Any]:
        benchmark_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark", {})
        )
        directive_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_directive", {})
        )
        output_contract_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_output_contract", {})
        )
        success_rubric_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_success_rubric", {})
        )
        operator_value_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_operator_value", {})
        )
        workspace_id = str(
            benchmark_payload.get("reference_workspace_id", "")
            or "workspace_trusted_source_guided_successor_iteration_live_e"
        ).strip() or "workspace_trusted_source_guided_successor_iteration_live_e"
        workspace_root = self.package_root / "novali-active_workspace" / workspace_id
        successor_evidence_doc = (
            self.package_root / "docs" / "SUCCESSOR_IMPROVEMENT_EVIDENCE.md"
        )
        successor_manifest_path = (
            self.package_root
            / "runtime_data"
            / "acceptance_evidence"
            / "successor_improvement"
            / "package_successor_improvement_manifest.json"
        )
        directive_file_path = Path(
            str(
                directive_payload.get("directive_file_path", "")
                or self.package_root
                / "manual_acceptance_samples"
                / "successor_package_readiness_benchmark_directive.json"
            )
        )

        def _read_json(path: Path) -> dict[str, Any]:
            try:
                return json.loads(path.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError):
                return {}

        def _resolve_output_path(output_row: Mapping[str, Any]) -> tuple[Path, str]:
            expected_relative = str(
                output_row.get("expected_workspace_relative_path", "") or ""
            ).strip()
            if expected_relative:
                packaged_candidate = self.package_root / Path(expected_relative)
                if packaged_candidate.exists():
                    return packaged_candidate, "packaged_workspace_copy"
            fallback_candidates = []
            reference_proof_path = str(
                output_row.get("reference_proof_path", "") or ""
            ).strip()
            if reference_proof_path:
                fallback_candidates.append(Path(reference_proof_path))
            for candidate in fallback_candidates:
                try:
                    if candidate.exists():
                        return candidate, "reference_proof_path"
                except OSError:
                    continue
            if expected_relative:
                return self.package_root / Path(expected_relative), "expected_missing"
            return workspace_root, "workspace_root_fallback"

        expected_outputs = [
            dict(item)
            for item in list(output_contract_payload.get("required_outputs", []) or [])
            + list(output_contract_payload.get("optional_outputs", []) or [])
            if isinstance(item, Mapping)
        ]
        output_rows: list[dict[str, Any]] = []
        for item in expected_outputs:
            resolved_path, resolution_state = _resolve_output_path(item)
            exists = False
            file_size_bytes = 0
            try:
                exists = resolved_path.exists()
                if exists and resolved_path.is_file():
                    file_size_bytes = int(resolved_path.stat().st_size)
            except OSError:
                exists = False
                file_size_bytes = 0
            output_rows.append(
                {
                    "output_id": str(item.get("output_id", "") or ""),
                    "output_label": str(item.get("output_label", "") or "<none>"),
                    "required": bool(item.get("required", False)),
                    "artifact_path": str(resolved_path),
                    "artifact_exists": exists,
                    "artifact_state": "final" if exists else "missing",
                    "reviewable": bool(exists and file_size_bytes > 0),
                    "file_size_bytes": file_size_bytes,
                    "path_resolution_state": resolution_state,
                    "expected_workspace_relative_path": str(
                        item.get("expected_workspace_relative_path", "") or ""
                    ),
                    "reference_proof_path": str(
                        item.get("reference_proof_path", "") or ""
                    ),
                    "review_standard": str(item.get("review_standard", "") or ""),
                }
            )

        required_output_rows = [
            dict(item) for item in output_rows if bool(item.get("required", False))
        ]
        optional_output_rows = [
            dict(item) for item in output_rows if not bool(item.get("required", False))
        ]
        produced_required_rows = [
            dict(item)
            for item in required_output_rows
            if bool(item.get("artifact_exists", False))
        ]
        missing_required_rows = [
            dict(item)
            for item in required_output_rows
            if not bool(item.get("artifact_exists", False))
        ]
        produced_optional_rows = [
            dict(item)
            for item in optional_output_rows
            if bool(item.get("artifact_exists", False))
        ]
        reviewable_output_rows = [
            dict(item) for item in output_rows if bool(item.get("reviewable", False))
        ]
        output_by_id = {
            str(item.get("output_id", "") or ""): dict(item) for item in output_rows
        }
        readiness_evaluation_payload = _read_json(
            Path(
                str(
                    output_by_id.get("readiness_evaluation", {}).get("artifact_path", "")
                    or ""
                )
            )
        )
        missing_deliverables_payload = _read_json(
            Path(
                str(
                    output_by_id.get("missing_deliverables", {}).get("artifact_path", "")
                    or ""
                )
            )
        )
        handoff_refresh_manifest_payload = _read_json(
            Path(
                str(
                    output_by_id.get("handoff_refresh_manifest", {}).get(
                        "artifact_path", ""
                    )
                    or ""
                )
            )
        )
        unresolved_items = [
            dict(item)
            for item in list(
                missing_deliverables_payload.get("missing_required_deliverables", [])
                or []
            )
            if isinstance(item, Mapping)
        ]
        unresolved_labels = [
            str(item.get("deliverable_id", "") or "<unknown>")
            for item in unresolved_items
        ]
        review_gate_required = bool(
            unresolved_items
            or str(
                readiness_evaluation_payload.get("next_recommended_cycle", "") or ""
            ).strip()
            == "operator_review_required"
            or bool(
                readiness_evaluation_payload.get(
                    "successor_handoff_refresh_recommended", False
                )
            )
            or bool(
                handoff_refresh_manifest_payload.get("package_refresh_recommended", False)
            )
        )
        local_inputs_inspected = [
            {
                "input_id": "successor_improvement_doc",
                "input_label": "Packaged successor-improvement evidence doc",
                "path": str(successor_evidence_doc),
                "exists": bool(successor_evidence_doc.exists()),
            },
            {
                "input_id": "successor_improvement_manifest",
                "input_label": "Packaged successor-improvement manifest",
                "path": str(successor_manifest_path),
                "exists": bool(successor_manifest_path.exists()),
            },
            {
                "input_id": "benchmark_directive",
                "input_label": "Benchmark directive",
                "path": str(directive_file_path),
                "exists": bool(directive_file_path.exists()),
            },
        ] + [
            {
                "input_id": str(item.get("output_id", "") or ""),
                "input_label": str(item.get("output_label", "") or "<none>"),
                "path": str(item.get("artifact_path", "") or ""),
                "exists": bool(item.get("artifact_exists", False)),
            }
            for item in output_rows
        ]
        missing_required_count = len(missing_required_rows)
        produced_required_count = len(produced_required_rows)
        produced_optional_count = len(produced_optional_rows)
        reviewable_output_count = len(reviewable_output_rows)
        if missing_required_count == 0 and reviewable_output_count >= len(
            required_output_rows
        ):
            rubric_outcome = "pass_with_review_gate" if review_gate_required else "pass"
        elif produced_required_count > 0:
            rubric_outcome = "partial"
        else:
            rubric_outcome = "blocked"
        execution_state = {
            "pass": "local_first_execution_completed",
            "pass_with_review_gate": "local_first_execution_completed_review_gated",
            "partial": "local_first_execution_partial",
            "blocked": "local_first_execution_blocked",
            "failed": "local_first_execution_failed",
        }.get(rubric_outcome, "local_first_execution_partial")
        execution_label = {
            "pass": "Local-first benchmark run completed",
            "pass_with_review_gate": "Local-first benchmark run completed with review gate",
            "partial": "Local-first benchmark run partially completed",
            "blocked": "Local-first benchmark run blocked",
            "failed": "Local-first benchmark run failed",
        }.get(rubric_outcome, "Local-first benchmark run partially completed")
        produced_output_summary = (
            f"Produced {produced_required_count}/{len(required_output_rows)} required outputs and "
            f"{produced_optional_count}/{len(optional_output_rows)} optional outputs. "
            f"{reviewable_output_count} output artifact(s) are reviewable on disk."
        )
        if missing_required_rows:
            missing_output_summary = (
                "Missing required outputs: "
                + ", ".join(
                    str(item.get("output_label", "") or "<none>")
                    for item in missing_required_rows
                )
            )
        elif unresolved_labels:
            missing_output_summary = (
                "No required outputs are missing. Unresolved deliverable signals remain: "
                + ", ".join(unresolved_labels)
                + "."
            )
        else:
            missing_output_summary = (
                "No required outputs are missing and no unresolved deliverable signals are currently recorded."
            )
        execution_summary = (
            f"Local-first inspection of the packaged successor-improvement evidence, directive, and workspace readiness bundle found "
            f"{produced_required_count}/{len(required_output_rows)} required outputs and "
            f"{produced_optional_count}/{len(optional_output_rows)} optional outputs."
        )
        evidence_summary = str(
            readiness_evaluation_payload.get("readiness_summary", "")
            or handoff_refresh_manifest_payload.get("package_refresh_summary", "")
            or benchmark_payload.get("input_summary", "")
            or "No benchmark evidence summary is recorded."
        )
        what_this_run_proves_summary = (
            "This benchmark run proves NOVALI can inspect current local repo, package, and workspace evidence to assemble a reviewable successor package-readiness bundle outside the demo lane without broadening authority."
        )
        if unresolved_labels:
            what_remains_unresolved_summary = (
                "The bundle is reviewable, but the missing-deliverables summary still records "
                + ", ".join(unresolved_labels)
                + " as requiring refreshed canonical handoff evidence before rebuild or promotion."
            )
        elif review_gate_required:
            what_remains_unresolved_summary = (
                "The bundle is complete and reviewable, but explicit operator review remains required before reuse or promotion."
            )
        else:
            what_remains_unresolved_summary = (
                "No major unresolved benchmark blockers are currently recorded."
            )
        review_gate_summary = (
            "Review is still recommended because the readiness bundle supports handoff-refresh judgment, but it remains support-only evidence and does not authorize promotion automatically."
            if review_gate_required
            else "No additional review gate is currently signaled by the local-first benchmark outputs."
        )
        next_improvement_target_summary = (
            "Tighten the link between the missing-deliverables summary and the next canonical handoff refresh so bundle completeness and promotion gating stay aligned."
        )
        execution_signature = _stable_hash_payload(
            {
                "workflow_id": benchmark_payload.get("workflow_id", ""),
                "produced_required_output_count": produced_required_count,
                "produced_optional_output_count": produced_optional_count,
                "missing_required_output_count": missing_required_count,
                "rubric_outcome": rubric_outcome,
                "unresolved_labels": unresolved_labels,
            }
        )
        benchmark_execution_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_EXECUTION_SCHEMA_NAME,
            "schema_version": CONTROLLER_REAL_WORK_BENCHMARK_EXECUTION_SCHEMA_VERSION,
            "execution_signature": execution_signature,
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "workflow_name": str(benchmark_payload.get("workflow_name", "") or ""),
            "directive_id": str(directive_payload.get("directive_id", "") or ""),
            "workspace_id": workspace_id,
            "workspace_root": str(workspace_root),
            "selected_path_id": "local",
            "selected_path_label": "Local Controller handling",
            "allowed_bounded_path_set": [
                "local",
                "librarian",
                "verifier",
                "sequential_librarian_then_verifier",
            ],
            "benchmark_execution_state": execution_state,
            "execution_label": execution_label,
            "local_first_execution": True,
            "inputs_inspected": local_inputs_inspected,
            "required_outputs_expected": len(required_output_rows),
            "required_outputs_produced": produced_required_count,
            "optional_outputs_produced": produced_optional_count,
            "missing_required_outputs": missing_required_count,
            "execution_summary": execution_summary,
            "evidence_summary": evidence_summary,
            "what_this_run_proves_summary": what_this_run_proves_summary,
            "what_this_first_run_proves_summary": what_this_run_proves_summary,
            "what_remains_unresolved_summary": what_remains_unresolved_summary,
            "review_gate_required": review_gate_required,
            "review_gate_summary": review_gate_summary,
            "next_improvement_target_summary": next_improvement_target_summary,
            "advisory_only": True,
            "non_authoritative_note": (
                "This benchmark execution record is operator support only, does not authorize policy change, and does not create a second authority path."
            ),
        }
        benchmark_execution_history_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_EXECUTION_HISTORY_SCHEMA_NAME,
            "schema_version": CONTROLLER_REAL_WORK_BENCHMARK_EXECUTION_HISTORY_SCHEMA_VERSION,
            "entry_count": 1,
            "entries": [
                {
                    "recorded_at": _now(),
                    "execution_signature": execution_signature,
                    "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
                    "benchmark_execution_state": execution_state,
                    "rubric_outcome": rubric_outcome,
                    "produced_required_output_count": produced_required_count,
                    "missing_required_output_count": missing_required_count,
                    "review_gate_required": review_gate_required,
                }
            ],
            "advisory_only": True,
            "non_authoritative_note": (
                "This benchmark execution history records the current bounded run only and does not authorize policy change."
            ),
        }
        benchmark_result_summary_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_RESULT_SUMMARY_SCHEMA_NAME,
            "schema_version": CONTROLLER_REAL_WORK_BENCHMARK_RESULT_SUMMARY_SCHEMA_VERSION,
            "result_summary_title": "Benchmark run result",
            "rubric_outcome": rubric_outcome,
            "result_summary": (
                f"The current local-first benchmark run is classified as {rubric_outcome}."
            ),
            "execution_summary": execution_summary,
            "evidence_summary": evidence_summary,
            "produced_output_summary": produced_output_summary,
            "what_this_run_proves_summary": what_this_run_proves_summary,
            "what_this_first_run_proves_summary": what_this_run_proves_summary,
            "what_remains_unresolved_summary": what_remains_unresolved_summary,
            "operator_value_summary": (
                "This run already delivers operator value by turning the successor-readiness bundle into a bounded, reviewable decision aid for standalone handoff refresh judgment."
            ),
            "useful_now_summary": (
                "The operator can now review a concrete readiness bundle, its supporting evidence, and the remaining gate instead of relying on the benchmark definition alone."
            ),
            "review_gate_summary": review_gate_summary,
            "next_improvement_target_summary": next_improvement_target_summary,
            "advisory_only": True,
            "non_authoritative_note": (
                "This result summary explains the first benchmark run and does not authorize policy change or promotion."
            ),
        }
        benchmark_output_inventory_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_OUTPUT_INVENTORY_SCHEMA_NAME,
            "schema_version": CONTROLLER_REAL_WORK_BENCHMARK_OUTPUT_INVENTORY_SCHEMA_VERSION,
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "output_rows": output_rows,
            "required_outputs_expected": required_output_rows,
            "required_outputs_produced": produced_required_rows,
            "optional_outputs_produced": produced_optional_rows,
            "missing_required_outputs": missing_required_rows,
            "produced_required_output_count": produced_required_count,
            "produced_optional_output_count": produced_optional_count,
            "missing_required_output_count": missing_required_count,
            "reviewable_output_count": reviewable_output_count,
            "reviewable_outputs_exist": bool(reviewable_output_rows),
            "produced_output_summary": produced_output_summary,
            "missing_output_summary": missing_output_summary,
            "unresolved_items": unresolved_items,
            "advisory_only": True,
            "non_authoritative_note": (
                "This output inventory records what the benchmark run produced and does not authorize policy change or hidden completion claims."
            ),
        }
        dimension_results = [
            {
                "dimension_id": "output_completeness",
                "result": "satisfied" if missing_required_count == 0 else "unsatisfied",
                "summary": (
                    "All required outputs are present."
                    if missing_required_count == 0
                    else f"{missing_required_count} required outputs remain missing."
                ),
            },
            {
                "dimension_id": "output_reviewability",
                "result": (
                    "satisfied"
                    if reviewable_output_count >= len(required_output_rows)
                    else "mixed"
                ),
                "summary": (
                    f"{reviewable_output_count} output artifact(s) are reviewable on disk."
                ),
            },
            {
                "dimension_id": "boundedness_preserved",
                "result": "satisfied",
                "summary": "The run stayed local-first and within the existing bounded path set.",
            },
            {
                "dimension_id": "operator_value_delivered",
                "result": "satisfied" if produced_required_count > 0 else "unsatisfied",
                "summary": (
                    "The run yields a concrete readiness bundle for handoff-refresh review."
                    if produced_required_count > 0
                    else "The run did not yield a usable readiness bundle yet."
                ),
            },
            {
                "dimension_id": "governance_posture_preserved",
                "result": "satisfied",
                "summary": review_gate_summary,
            },
        ]
        benchmark_rubric_result_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_RUBRIC_RESULT_SCHEMA_NAME,
            "schema_version": CONTROLLER_REAL_WORK_BENCHMARK_RUBRIC_RESULT_SCHEMA_VERSION,
            "rubric_title": str(
                success_rubric_payload.get("rubric_title", "") or "Benchmark rubric result"
            ),
            "rubric_outcome": rubric_outcome,
            "rubric_result_label": rubric_outcome,
            "rubric_result_summary": (
                f"Classified as {rubric_outcome}: all required outputs are reviewable on disk, and the run remains explicitly review-gated."
                if rubric_outcome == "pass_with_review_gate"
                else f"Classified as {rubric_outcome}: {missing_output_summary.lower()}"
            ),
            "why_result_classification_summary": (
                "All five required outputs exist and are reviewable, but the readiness bundle still points to explicit operator review before reuse or promotion."
                if rubric_outcome == "pass_with_review_gate"
                else "The benchmark run does not yet satisfy the stronger complete-and-reviewable standard."
            ),
            "dimension_results": dimension_results,
            "review_gate_required": review_gate_required,
            "review_gate_summary": review_gate_summary,
            "produced_required_output_count": produced_required_count,
            "missing_required_output_count": missing_required_count,
            "advisory_only": True,
            "non_authoritative_note": (
                "This rubric result judges the bounded benchmark run and does not authorize policy change or automatic promotion."
            ),
        }

        updated_benchmark_payload = dict(benchmark_payload)
        updated_benchmark_payload.update(
            {
                "benchmark_execution_state": execution_state,
                "latest_execution_signature": execution_signature,
                "latest_rubric_outcome": rubric_outcome,
                "required_outputs_produced_count": produced_required_count,
                "missing_required_output_count": missing_required_count,
                "optional_outputs_produced_count": produced_optional_count,
                "review_gate_required": review_gate_required,
                "future_execution_note": (
                    "Rc47 preserves the benchmark identity, reruns it local-first, and adds explicit closure / repeatability evidence without broadening authority."
                ),
            }
        )

        save_controller_real_work_benchmark(
            updated_benchmark_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_execution(
            benchmark_execution_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_execution_history(
            benchmark_execution_history_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_result_summary(
            benchmark_result_summary_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_output_inventory(
            benchmark_output_inventory_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_rubric_result(
            benchmark_rubric_result_payload,
            root=self.operator_root,
        )
        return {
            "controller_real_work_benchmark": updated_benchmark_payload,
            "controller_real_work_benchmark_execution": benchmark_execution_payload,
            "controller_real_work_benchmark_execution_history": (
                benchmark_execution_history_payload
            ),
            "controller_real_work_benchmark_result_summary": (
                benchmark_result_summary_payload
            ),
            "controller_real_work_benchmark_output_inventory": (
                benchmark_output_inventory_payload
            ),
            "controller_real_work_benchmark_rubric_result": (
                benchmark_rubric_result_payload
            ),
            "controller_real_work_benchmark_execution_path": str(
                controller_real_work_benchmark_execution_path(root=self.operator_root)
            ),
            "controller_real_work_benchmark_execution_history_path": str(
                controller_real_work_benchmark_execution_history_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_result_summary_path": str(
                controller_real_work_benchmark_result_summary_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_output_inventory_path": str(
                controller_real_work_benchmark_output_inventory_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_rubric_result_path": str(
                controller_real_work_benchmark_rubric_result_path(
                    root=self.operator_root
                )
            ),
        }

    def _save_real_work_benchmark_closure_views(
        self,
        *,
        operator_snapshot: dict[str, Any],
    ) -> dict[str, Any]:
        benchmark_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark", {})
        )
        directive_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_directive", {})
        )
        execution_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_execution", {})
        )
        output_inventory_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_output_inventory", {})
        )
        rubric_result_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_rubric_result", {})
        )

        def _read_json(path: Path) -> dict[str, Any]:
            try:
                return json.loads(path.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError):
                return {}

        output_rows = [
            dict(item)
            for item in list(output_inventory_payload.get("output_rows", []) or [])
            if isinstance(item, Mapping)
        ]
        required_rows = [
            dict(item) for item in output_rows if bool(item.get("required", False))
        ]
        optional_rows = [
            dict(item) for item in output_rows if not bool(item.get("required", False))
        ]
        reproduced_required_rows = [
            dict(item)
            for item in list(
                output_inventory_payload.get("required_outputs_produced", []) or []
            )
            if isinstance(item, Mapping)
        ]
        reproduced_optional_rows = [
            dict(item)
            for item in list(
                output_inventory_payload.get("optional_outputs_produced", []) or []
            )
            if isinstance(item, Mapping)
        ]
        missing_required_rows = [
            dict(item)
            for item in list(
                output_inventory_payload.get("missing_required_outputs", []) or []
            )
            if isinstance(item, Mapping)
        ]
        unresolved_items = [
            dict(item)
            for item in list(output_inventory_payload.get("unresolved_items", []) or [])
            if isinstance(item, Mapping)
        ]

        required_output_ids = [
            str(item.get("output_id", "") or "")
            for item in required_rows
            if str(item.get("output_id", "") or "").strip()
        ]
        optional_output_ids = [
            str(item.get("output_id", "") or "")
            for item in optional_rows
            if str(item.get("output_id", "") or "").strip()
        ]
        reproduced_required_ids = [
            str(item.get("output_id", "") or "")
            for item in reproduced_required_rows
            if str(item.get("output_id", "") or "").strip()
        ]
        reproduced_optional_ids = [
            str(item.get("output_id", "") or "")
            for item in reproduced_optional_rows
            if str(item.get("output_id", "") or "").strip()
        ]
        missing_required_ids = [
            str(item.get("output_id", "") or "")
            for item in missing_required_rows
            if str(item.get("output_id", "") or "").strip()
        ]
        stable_output_ids = sorted(
            set(required_output_ids).intersection(reproduced_required_ids)
            | set(optional_output_ids).intersection(reproduced_optional_ids)
        )

        review_gate_required = bool(execution_payload.get("review_gate_required", False))
        allowed_bounded_path_set = [
            "local",
            "librarian",
            "verifier",
            "sequential_librarian_then_verifier",
        ]
        required_outputs_reproduced_successfully = (
            len(reproduced_required_rows) == len(required_rows)
            and len(missing_required_rows) == 0
        )
        optional_outputs_reproduced_successfully = len(reproduced_optional_rows) == len(
            optional_rows
        )
        run_reproduced_successfully = (
            required_outputs_reproduced_successfully
            and str(execution_payload.get("selected_path_id", "") or "") == "local"
            and str(rubric_result_payload.get("rubric_outcome", "") or "")
            in {"pass", "pass_with_review_gate"}
        )

        handoff_layout_manifest_path = self.package_root / "handoff_layout_manifest.json"
        image_archive_manifest_path = (
            self.package_root / "image" / "image_archive_manifest.json"
        )
        bundled_image_archive_path = _preferred_package_image_archive(self.package_root)
        successor_manifest_path = (
            self.package_root
            / "runtime_data"
            / "acceptance_evidence"
            / "successor_improvement"
            / "package_successor_improvement_manifest.json"
        )
        handoff_layout_manifest = _read_json(handoff_layout_manifest_path)
        image_archive_manifest = _read_json(image_archive_manifest_path)
        successor_manifest = _read_json(successor_manifest_path)
        refreshed_handoff_evidence_present = bool(
            handoff_layout_manifest_path.exists()
            and successor_manifest_path.exists()
            and (
                bundled_image_archive_path.exists()
                or bool(image_archive_manifest.get("archive_present", False))
            )
        )

        successor_bundle_rows = [
            dict(item)
            for item in unresolved_items
            if str(item.get("deliverable_id", "") or "").strip()
            == "successor_readiness_bundle"
        ]
        successor_bundle_reason = str(
            successor_bundle_rows[0].get("reason", "") if successor_bundle_rows else ""
        ).strip()

        if successor_bundle_rows:
            if refreshed_handoff_evidence_present and run_reproduced_successfully:
                successor_bundle_state = "narrowed"
                current_blocker_summary = (
                    "The original successor_readiness_bundle blocker is still recorded in the missing-deliverables summary, but the rebuilt handoff now exists and the repeat run reproduced the full readiness bundle. The remaining blocker is explicit operator review of the rebuilt successor package before promotion."
                )
            else:
                successor_bundle_state = "still_unresolved"
                current_blocker_summary = (
                    successor_bundle_reason
                    or "The successor_readiness_bundle blocker is still recorded without enough rebuilt-handoff evidence to narrow it yet."
                )
        else:
            successor_bundle_state = "closed_with_review_gate"
            current_blocker_summary = (
                "The successor_readiness_bundle blocker is no longer recorded as missing, but explicit operator review still remains required before promotion."
            )

        if run_reproduced_successfully and optional_outputs_reproduced_successfully:
            repeatability_state = (
                "reproduced_cleanly_review_gated"
                if review_gate_required
                else "reproduced_cleanly"
            )
            repeatability_label = (
                "Reproduced cleanly with review gate"
                if review_gate_required
                else "Reproduced cleanly"
            )
            repeatability_summary = (
                f"The repeat run reproduced {len(reproduced_required_rows)}/{len(required_rows)} required outputs and "
                f"{len(reproduced_optional_rows)}/{len(optional_rows)} optional outputs from local packaged/workspace evidence."
            )
        elif required_outputs_reproduced_successfully:
            repeatability_state = "required_outputs_reproduced_optional_mixed"
            repeatability_label = "Required outputs reproduced"
            repeatability_summary = (
                f"All required outputs reproduced, but only {len(reproduced_optional_rows)}/{len(optional_rows)} optional outputs reproduced in the repeat run."
            )
        else:
            repeatability_state = "not_cleanly_reproduced"
            repeatability_label = "Not reproduced cleanly"
            repeatability_summary = (
                f"Only {len(reproduced_required_rows)}/{len(required_rows)} required outputs reproduced in the repeat run."
            )

        if run_reproduced_successfully and successor_bundle_state == "narrowed":
            closure_state = "bundle_gap_narrowed_review_gated"
            closure_label = "Bundle gap narrowed"
            closure_summary = (
                "Rc47 reproduced the benchmark cleanly and narrowed the successor_readiness_bundle gap by pairing the repeat run with a rebuilt canonical handoff and bundled archive evidence."
            )
        elif run_reproduced_successfully and successor_bundle_state == "closed_with_review_gate":
            closure_state = "bundle_closed_with_review_gate"
            closure_label = "Bundle closed with review gate"
            closure_summary = (
                "Rc47 reproduced the benchmark cleanly and the successor_readiness_bundle blocker is no longer recorded as missing, while explicit operator review remains required."
            )
        elif run_reproduced_successfully:
            closure_state = "bundle_still_unresolved_review_gated"
            closure_label = "Bundle still unresolved"
            closure_summary = (
                "Rc47 reproduced the benchmark cleanly, but the successor_readiness_bundle blocker still remains unresolved."
            )
        elif reproduced_required_rows:
            closure_state = "repeatability_partial"
            closure_label = "Closure partial"
            closure_summary = (
                "Rc47 reproduced part of the benchmark bundle, but repeatability and closure remain incomplete."
            )
        else:
            closure_state = "repeatability_blocked"
            closure_label = "Closure blocked"
            closure_summary = (
                "Rc47 could not reproduce the readiness bundle cleanly enough to improve closure evidence."
            )

        if refreshed_handoff_evidence_present and run_reproduced_successfully:
            promotion_readiness_state = "review_gated_rebuild_evidence_ready"
            promotion_readiness_label = "Rebuild evidence ready with review gate"
            promotion_readiness_summary = (
                "The rebuilt handoff, bundled image archive, and repeat benchmark outputs are all present. Promotion readiness is stronger than rc46, but it remains explicitly review-gated and non-authoritative."
            )
        else:
            promotion_readiness_state = "promotion_evidence_incomplete"
            promotion_readiness_label = "Promotion evidence incomplete"
            promotion_readiness_summary = (
                "The repeat run did not supply enough rebuilt-handoff evidence to tighten the promotion-ready story yet."
            )

        rc46_reference = {
            "reference_release": "rc46",
            "reference_source": "preserved_rc46_benchmark_posture",
            "benchmark_execution_state": "local_first_execution_completed_review_gated",
            "rubric_outcome": "pass_with_review_gate",
            "required_outputs_produced": len(required_rows),
            "optional_outputs_produced": len(optional_rows),
            "missing_required_outputs": 0,
            "successor_readiness_bundle_state": "still_unresolved",
            "selected_path_id": "local",
        }
        changed_aspects = [
            {
                "aspect_id": "repeatability_evidence",
                "summary": "Rc47 adds explicit repeatability evidence for the selected benchmark lane.",
            },
            {
                "aspect_id": "promotion_readiness_explanation",
                "summary": "Rc47 adds explicit rebuilt-handoff and promotion-readiness evidence without widening authority.",
            },
        ]
        if successor_bundle_state != str(
            rc46_reference.get("successor_readiness_bundle_state", "") or ""
        ):
            changed_aspects.append(
                {
                    "aspect_id": "successor_readiness_bundle_state",
                    "summary": (
                        f"successor_readiness_bundle moved from {rc46_reference['successor_readiness_bundle_state']} to {successor_bundle_state}."
                    ),
                }
            )
        stable_aspects = [
            {
                "aspect_id": "workflow_identity",
                "summary": (
                    "The selected benchmark workflow stayed fixed at successor_package_readiness_review_bundle_refresh."
                ),
            },
            {
                "aspect_id": "directive_path",
                "summary": (
                    "The directive path stayed fixed at manual_acceptance_samples/successor_package_readiness_benchmark_directive.json."
                ),
            },
            {
                "aspect_id": "bounded_path_set",
                "summary": "The repeat run stayed local-first inside the same four bounded path options.",
            },
            {
                "aspect_id": "rubric_outcome",
                "summary": (
                    f"The rubric outcome remained {str(rubric_result_payload.get('rubric_outcome', '') or '<none>')}."
                ),
            },
        ]
        delta_summary = (
            "Compared with rc46, rc47 reproduces the same reviewable readiness bundle again and makes the remaining promotion blocker more decisive: the gap narrows from missing refreshed canonical handoff evidence to pending operator review of the rebuilt handoff."
            if successor_bundle_state == "narrowed"
            else "Compared with rc46, rc47 reproduces the benchmark again but does not materially narrow the remaining successor_readiness_bundle blocker."
        )

        closure_signature = _stable_hash_payload(
            {
                "workflow_id": benchmark_payload.get("workflow_id", ""),
                "closure_state": closure_state,
                "repeatability_state": repeatability_state,
                "promotion_readiness_state": promotion_readiness_state,
                "successor_bundle_state": successor_bundle_state,
                "rubric_outcome": rubric_result_payload.get("rubric_outcome", ""),
            }
        )
        closure_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_CLOSURE_SCHEMA_NAME,
            "schema_version": CONTROLLER_REAL_WORK_BENCHMARK_CLOSURE_SCHEMA_VERSION,
            "closure_signature": closure_signature,
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "workflow_name": str(benchmark_payload.get("workflow_name", "") or ""),
            "directive_file_path": str(
                directive_payload.get("directive_file_path", "") or ""
            ),
            "selected_path_id": "local",
            "allowed_bounded_path_set": allowed_bounded_path_set,
            "benchmark_closure_state": closure_state,
            "closure_label": closure_label,
            "run_reproduced_successfully": run_reproduced_successfully,
            "required_outputs_reproduced_successfully": (
                required_outputs_reproduced_successfully
            ),
            "optional_outputs_reproduced_successfully": (
                optional_outputs_reproduced_successfully
            ),
            "successor_readiness_bundle_state": successor_bundle_state,
            "closure_summary": closure_summary,
            "closure_evidence_summary": (
                "Closure is judged from the repeat output inventory, bundled handoff manifests, bundled image archive manifest, and packaged successor-improvement evidence."
            ),
            "what_remains_unresolved_summary": current_blocker_summary,
            "advisory_only": True,
            "non_authoritative_note": (
                "This benchmark closure record is operator support only, does not authorize policy change, and does not create a second authority path."
            ),
        }
        closure_history_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_CLOSURE_HISTORY_SCHEMA_NAME,
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_CLOSURE_HISTORY_SCHEMA_VERSION
            ),
            "entry_count": 1,
            "entries": [
                {
                    "recorded_at": _now(),
                    "closure_signature": closure_signature,
                    "benchmark_closure_state": closure_state,
                    "successor_readiness_bundle_state": successor_bundle_state,
                    "run_reproduced_successfully": run_reproduced_successfully,
                }
            ],
            "advisory_only": True,
            "non_authoritative_note": (
                "This benchmark closure history records the current bounded rc47 closure posture only and does not authorize policy change."
            ),
        }
        repeatability_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_REPEATABILITY_SCHEMA_NAME,
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_REPEATABILITY_SCHEMA_VERSION
            ),
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "selected_path_id": "local",
            "allowed_bounded_path_set": allowed_bounded_path_set,
            "repeatability_state": repeatability_state,
            "repeatability_label": repeatability_label,
            "repeatability_summary": repeatability_summary,
            "repeat_execution_summary": (
                "Rc47 re-ran the selected benchmark from local packaged/workspace evidence in a fresh bounded context and compared the reproduced bundle against the preserved rc46 posture."
            ),
            "required_outputs_previously_produced": required_output_ids,
            "required_outputs_reproduced_now": reproduced_required_ids,
            "optional_outputs_previously_produced": optional_output_ids,
            "optional_outputs_reproduced_now": reproduced_optional_ids,
            "stable_output_ids": stable_output_ids,
            "materially_changed_output_ids": [],
            "still_missing_output_ids": missing_required_ids,
            "advisory_only": True,
            "non_authoritative_note": (
                "This repeatability record is operator support only and does not authorize policy change or automatic promotion."
            ),
        }
        repeatability_history_payload = {
            "schema_name": (
                CONTROLLER_REAL_WORK_BENCHMARK_REPEATABILITY_HISTORY_SCHEMA_NAME
            ),
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_REPEATABILITY_HISTORY_SCHEMA_VERSION
            ),
            "entry_count": 1,
            "entries": [
                {
                    "recorded_at": _now(),
                    "closure_signature": closure_signature,
                    "repeatability_state": repeatability_state,
                    "required_outputs_reproduced_successfully": (
                        required_outputs_reproduced_successfully
                    ),
                    "optional_outputs_reproduced_successfully": (
                        optional_outputs_reproduced_successfully
                    ),
                }
            ],
            "advisory_only": True,
            "non_authoritative_note": (
                "This repeatability history records the current bounded rc47 posture only and does not authorize policy change."
            ),
        }
        promotion_readiness_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_PROMOTION_READINESS_SCHEMA_NAME,
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_PROMOTION_READINESS_SCHEMA_VERSION
            ),
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "selected_path_id": "local",
            "allowed_bounded_path_set": allowed_bounded_path_set,
            "promotion_readiness_state": promotion_readiness_state,
            "promotion_readiness_label": promotion_readiness_label,
            "promotion_readiness_summary": promotion_readiness_summary,
            "refreshed_handoff_evidence_present": refreshed_handoff_evidence_present,
            "handoff_layout_manifest_path": str(handoff_layout_manifest_path),
            "image_archive_manifest_path": str(image_archive_manifest_path),
            "successor_manifest_path": str(successor_manifest_path),
            "promotion_blocker_summary": current_blocker_summary,
            "review_gate_required": review_gate_required,
            "advisory_only": True,
            "non_authoritative_note": (
                "This promotion-readiness record is support-only evidence, does not authorize policy change, and does not authorize promotion automatically."
            ),
        }
        unresolved_bundle_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_UNRESOLVED_BUNDLE_SCHEMA_NAME,
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_UNRESOLVED_BUNDLE_SCHEMA_VERSION
            ),
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "selected_path_id": "local",
            "allowed_bounded_path_set": allowed_bounded_path_set,
            "bundle_id": "successor_readiness_bundle",
            "bundle_state_label": successor_bundle_state.replace("_", " "),
            "successor_readiness_bundle_state": successor_bundle_state,
            "prior_bundle_state": str(
                rc46_reference.get("successor_readiness_bundle_state", "") or ""
            ),
            "original_missing_deliverable_reason": successor_bundle_reason,
            "refreshed_handoff_evidence_present": refreshed_handoff_evidence_present,
            "unresolved_bundle_summary": (
                "Rc47 narrows the successor_readiness_bundle blocker by adding rebuilt-handoff evidence and a clean repeat run, but promotion still remains review-gated."
                if successor_bundle_state == "narrowed"
                else current_blocker_summary
            ),
            "current_blocker_summary": current_blocker_summary,
            "evidence_supporting_current_state": [
                {
                    "evidence_id": "handoff_layout_manifest",
                    "path": str(handoff_layout_manifest_path),
                    "exists": bool(handoff_layout_manifest_path.exists()),
                },
                {
                    "evidence_id": "image_archive_manifest",
                    "path": str(image_archive_manifest_path),
                    "exists": bool(image_archive_manifest_path.exists()),
                },
                {
                    "evidence_id": "successor_improvement_manifest",
                    "path": str(successor_manifest_path),
                    "exists": bool(successor_manifest_path.exists()),
                },
            ],
            "advisory_only": True,
            "non_authoritative_note": (
                "This unresolved-bundle record clarifies the remaining successor bundle gap and does not authorize policy change or promotion."
            ),
        }
        delta_from_rc46_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_DELTA_FROM_RC46_SCHEMA_NAME,
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_DELTA_FROM_RC46_SCHEMA_VERSION
            ),
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "selected_path_id": "local",
            "allowed_bounded_path_set": allowed_bounded_path_set,
            "comparison_release_label": "rc46 -> rc47",
            "delta_label": "Delta from rc46",
            "baseline_reference": rc46_reference,
            "current_execution_state": str(
                execution_payload.get("benchmark_execution_state", "") or ""
            ),
            "current_rubric_outcome": str(
                rubric_result_payload.get("rubric_outcome", "") or ""
            ),
            "current_successor_readiness_bundle_state": successor_bundle_state,
            "stable_aspects": stable_aspects,
            "changed_aspects": changed_aspects,
            "delta_summary": delta_summary,
            "what_changed_summary": (
                "Rc47 adds explicit closure, repeatability, unresolved-bundle, and promotion-readiness evidence on top of the rc46 first-run benchmark posture."
            ),
            "advisory_only": True,
            "non_authoritative_note": (
                "This delta record compares rc47 against the preserved rc46 benchmark posture and does not authorize policy change."
            ),
        }

        updated_benchmark_payload = dict(benchmark_payload)
        updated_benchmark_payload.update(
            {
                "benchmark_closure_state": closure_state,
                "repeatability_state": repeatability_state,
                "promotion_readiness_state": promotion_readiness_state,
                "successor_readiness_bundle_state": successor_bundle_state,
                "latest_closure_signature": closure_signature,
                "future_execution_note": (
                    "Rc47 preserves the selected benchmark lane, reruns it cleanly, and records explicit closure / repeatability evidence without broadening authority."
                ),
            }
        )

        save_controller_real_work_benchmark(
            updated_benchmark_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_closure(
            closure_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_closure_history(
            closure_history_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_repeatability(
            repeatability_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_repeatability_history(
            repeatability_history_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_promotion_readiness(
            promotion_readiness_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_unresolved_bundle(
            unresolved_bundle_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_delta_from_rc46(
            delta_from_rc46_payload,
            root=self.operator_root,
        )
        return {
            "controller_real_work_benchmark": updated_benchmark_payload,
            "controller_real_work_benchmark_closure": closure_payload,
            "controller_real_work_benchmark_closure_history": closure_history_payload,
            "controller_real_work_benchmark_repeatability": repeatability_payload,
            "controller_real_work_benchmark_repeatability_history": (
                repeatability_history_payload
            ),
            "controller_real_work_benchmark_promotion_readiness": (
                promotion_readiness_payload
            ),
            "controller_real_work_benchmark_unresolved_bundle": (
                unresolved_bundle_payload
            ),
            "controller_real_work_benchmark_delta_from_rc46": (
                delta_from_rc46_payload
            ),
            "controller_real_work_benchmark_closure_path": str(
                controller_real_work_benchmark_closure_path(root=self.operator_root)
            ),
            "controller_real_work_benchmark_closure_history_path": str(
                controller_real_work_benchmark_closure_history_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_repeatability_path": str(
                controller_real_work_benchmark_repeatability_path(root=self.operator_root)
            ),
            "controller_real_work_benchmark_repeatability_history_path": str(
                controller_real_work_benchmark_repeatability_history_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_promotion_readiness_path": str(
                controller_real_work_benchmark_promotion_readiness_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_unresolved_bundle_path": str(
                controller_real_work_benchmark_unresolved_bundle_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_delta_from_rc46_path": str(
                controller_real_work_benchmark_delta_from_rc46_path(
                    root=self.operator_root
                )
            ),
        }

    def _save_real_work_benchmark_decision_views(
        self,
        *,
        operator_snapshot: dict[str, Any],
    ) -> dict[str, Any]:
        benchmark_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark", {})
        )
        directive_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_directive", {})
        )
        output_inventory_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_output_inventory", {})
        )
        rubric_result_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_rubric_result", {})
        )
        closure_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_closure", {})
        )
        repeatability_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_repeatability", {})
        )
        promotion_readiness_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_promotion_readiness", {})
        )
        unresolved_bundle_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_unresolved_bundle", {})
        )
        delta_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_delta_from_rc46", {})
        )

        allowed_bounded_path_set = [
            "local",
            "librarian",
            "verifier",
            "sequential_librarian_then_verifier",
        ]
        output_rows = [
            dict(item)
            for item in list(output_inventory_payload.get("output_rows", []) or [])
            if isinstance(item, Mapping)
        ]
        required_output_count = int(
            output_inventory_payload.get("required_output_count", 0) or 0
        )
        if required_output_count == 0:
            required_output_count = sum(
                1 for item in output_rows if bool(item.get("required", False))
            )
        produced_required_output_count = int(
            output_inventory_payload.get("produced_required_output_count", 0) or 0
        )
        missing_required_output_count = int(
            output_inventory_payload.get("missing_required_output_count", 0) or 0
        )
        optional_output_count = int(
            output_inventory_payload.get("optional_output_count", 0) or 0
        )
        if optional_output_count == 0:
            optional_output_count = sum(
                1 for item in output_rows if not bool(item.get("required", False))
            )
        produced_optional_output_count = int(
            output_inventory_payload.get("produced_optional_output_count", 0) or 0
        )
        rubric_outcome = str(
            rubric_result_payload.get("rubric_outcome", "") or "<none>"
        )
        closure_state = str(
            closure_payload.get("benchmark_closure_state", "") or "<none>"
        )
        repeatability_state = str(
            repeatability_payload.get("repeatability_state", "") or "<none>"
        )
        promotion_readiness_state = str(
            promotion_readiness_payload.get("promotion_readiness_state", "") or "<none>"
        )
        successor_bundle_state = str(
            unresolved_bundle_payload.get("successor_readiness_bundle_state", "")
            or "<none>"
        )
        review_gate_required = bool(
            rubric_result_payload.get("review_gate_required", False)
            or promotion_readiness_payload.get("review_gate_required", False)
        )
        run_reproduced_cleanly = repeatability_state in {
            "reproduced_cleanly",
            "reproduced_cleanly_review_gated",
        }
        required_outputs_complete = (
            required_output_count > 0
            and produced_required_output_count == required_output_count
            and missing_required_output_count == 0
        )
        optional_outputs_complete = (
            optional_output_count == 0
            or produced_optional_output_count == optional_output_count
        )
        rebuilt_handoff_ready = (
            promotion_readiness_state == "review_gated_rebuild_evidence_ready"
        )
        only_review_blocker_remains = (
            rubric_outcome == "pass_with_review_gate"
            and run_reproduced_cleanly
            and required_outputs_complete
            and rebuilt_handoff_ready
            and successor_bundle_state in {"narrowed", "closed_with_review_gate"}
        )

        if only_review_blocker_remains:
            decision_state = "promote_with_review_gate"
        elif run_reproduced_cleanly and required_outputs_complete:
            decision_state = "hold_with_review_gate"
        elif produced_required_output_count > 0:
            decision_state = "defer_for_evidence"
        else:
            decision_state = "blocked"

        decision_label_map = {
            "promote_with_review_gate": "Promote with review gate",
            "hold_with_review_gate": "Hold with review gate",
            "defer_for_evidence": "Defer for evidence",
            "blocked": "Blocked",
        }
        next_action_map = {
            "promote_with_review_gate": "review_now",
            "hold_with_review_gate": "hold_until_specific_evidence",
            "defer_for_evidence": "defer_and_refresh_bundle",
            "blocked": "no_promotion_action",
        }
        next_action_label_map = {
            "review_now": "Review now",
            "hold_until_specific_evidence": "Hold until specific evidence",
            "defer_and_refresh_bundle": "Defer and refresh bundle",
            "no_promotion_action": "No promotion action",
        }
        next_operator_action = next_action_map[decision_state]
        human_decision_label = decision_label_map[decision_state]

        supporting_evidence_items = [
            "The selected benchmark reproduced cleanly in a fresh local-first bounded context.",
            f"Required outputs reproduced {produced_required_output_count}/{required_output_count}.",
            f"Optional outputs reproduced {produced_optional_output_count}/{optional_output_count}.",
            f"Rubric outcome remained {rubric_outcome}.",
        ]
        if rebuilt_handoff_ready:
            supporting_evidence_items.append(
                "Rebuilt canonical handoff evidence and bundled image-archive evidence are present."
            )
        if successor_bundle_state in {"narrowed", "closed_with_review_gate"}:
            supporting_evidence_items.append(
                "The successor_readiness_bundle gap is no longer a raw missing-artifact problem; it is now narrowed to explicit review-gated interpretation."
            )

        blocking_evidence_items: list[str] = []
        if successor_bundle_state == "narrowed":
            blocking_evidence_items.append(
                "The preserved missing-deliverables record still keeps successor_readiness_bundle visible as a narrowed blocker until a human reviewer signs off."
            )
        elif successor_bundle_state == "still_unresolved":
            blocking_evidence_items.append(
                "The successor_readiness_bundle still remains materially unresolved."
            )
        if review_gate_required:
            blocking_evidence_items.append(
                "Promotion remains explicitly review-gated and cannot be treated as automatic adoption."
            )
        if not rebuilt_handoff_ready:
            blocking_evidence_items.append(
                "Rebuilt-handoff evidence is not yet strong enough to support a review-gated promote packet."
            )
        if not required_outputs_complete:
            blocking_evidence_items.append(
                "Not all required benchmark outputs are reviewable on disk."
            )
        if not blocking_evidence_items:
            blocking_evidence_items.append(
                "No material blocking evidence is recorded beyond the standing human review gate."
            )

        if successor_bundle_state == "closed_with_review_gate":
            exact_final_blocker = (
                "No artifact gap remains in successor_readiness_bundle, but a human reviewer must still confirm the rebuilt successor package before any promotion step."
            )
            final_blocker_state = "review_confirmation_required"
            what_would_change_the_decision = (
                "A reviewer confirming the rebuilt successor package would clear the remaining human gate; contradictory evidence would lower the decision."
            )
        elif successor_bundle_state == "narrowed":
            exact_final_blocker = (
                "The preserved missing-deliverables record still flags successor_readiness_bundle, so promotion should proceed only after a human reviewer confirms the rebuilt canonical handoff, bundled image archive, and repeat benchmark outputs as the current successor readiness bundle."
            )
            final_blocker_state = "review_confirmation_required"
            what_would_change_the_decision = (
                "A reviewer confirming that the rebuilt canonical handoff and repeat benchmark bundle satisfy successor package readiness would turn this from a narrowed blocker into a cleared review-gated posture."
            )
        elif successor_bundle_state == "still_unresolved":
            exact_final_blocker = (
                "The successor_readiness_bundle still lacks enough refreshed local evidence to support a review-gated promote packet."
            )
            final_blocker_state = "evidence_gap_remaining"
            what_would_change_the_decision = (
                "A fresh local run that closes the successor_readiness_bundle gap and preserves the reviewable outputs would strengthen the decision."
            )
        else:
            exact_final_blocker = (
                "The current benchmark evidence does not yet support a stronger decision."
            )
            final_blocker_state = "decision_evidence_mixed"
            what_would_change_the_decision = (
                "Clearer rebuilt-handoff evidence and a stable repeatable bundle would strengthen the decision."
            )

        if decision_state == "promote_with_review_gate":
            decision_summary = (
                f"{human_decision_label}: the benchmark now supports a review-gated promote packet because the bundle reproduced cleanly, all required outputs are present, rebuilt-handoff evidence exists, and the remaining blocker is explicit human review rather than missing benchmark evidence."
            )
            promotion_decision_summary = (
                f"{human_decision_label}: support a review-gated promote packet for operator review. This is not automatic promotion; it is a bounded recommendation to review the rebuilt successor package now."
            )
            why_not_stronger_summary = (
                "This does not become unconditional promotion because the final step is still explicit human confirmation of the rebuilt successor package."
            )
        elif decision_state == "hold_with_review_gate":
            decision_summary = (
                f"{human_decision_label}: the benchmark is strong enough to hold under review gate, but the remaining blocker is still too material for a review-gated promote packet."
            )
            promotion_decision_summary = (
                f"{human_decision_label}: hold the bundle under review gate until the remaining blocker is resolved more decisively."
            )
            why_not_stronger_summary = (
                "The benchmark remains useful, but the remaining blocker is still stronger than a simple review confirmation."
            )
        elif decision_state == "defer_for_evidence":
            decision_summary = (
                f"{human_decision_label}: the benchmark remains useful, but more evidence is needed before hold/promote framing would be justified."
            )
            promotion_decision_summary = (
                f"{human_decision_label}: defer until the missing or mixed evidence is refreshed."
            )
            why_not_stronger_summary = (
                "The current bundle is not decisive enough to support a review-gated promote or hold packet."
            )
        else:
            decision_summary = (
                f"{human_decision_label}: the benchmark does not yet support a promotion decision packet because critical evidence is still missing or contradictory."
            )
            promotion_decision_summary = (
                f"{human_decision_label}: do not take promotion action from this benchmark packet yet."
            )
            why_not_stronger_summary = (
                "A stronger decision would overclaim beyond the current artifact chain."
            )

        review_first_artifact_paths = [
            str(
                operator_snapshot.get(
                    "controller_real_work_benchmark_promotion_readiness_path", ""
                )
                or controller_real_work_benchmark_promotion_readiness_path(
                    root=self.operator_root
                )
            ),
            str(
                operator_snapshot.get(
                    "controller_real_work_benchmark_unresolved_bundle_path", ""
                )
                or controller_real_work_benchmark_unresolved_bundle_path(
                    root=self.operator_root
                )
            ),
            str(
                operator_snapshot.get(
                    "controller_real_work_benchmark_output_inventory_path", ""
                )
                or controller_real_work_benchmark_output_inventory_path(
                    root=self.operator_root
                )
            ),
        ]
        secondary_artifact_paths = [
            str(
                operator_snapshot.get(
                    "controller_real_work_benchmark_closure_path", ""
                )
                or controller_real_work_benchmark_closure_path(root=self.operator_root)
            ),
            str(
                operator_snapshot.get(
                    "controller_real_work_benchmark_repeatability_path", ""
                )
                or controller_real_work_benchmark_repeatability_path(
                    root=self.operator_root
                )
            ),
            str(
                operator_snapshot.get(
                    "controller_real_work_benchmark_delta_from_rc46_path", ""
                )
                or controller_real_work_benchmark_delta_from_rc46_path(
                    root=self.operator_root
                )
            ),
        ]

        decision_signature = _stable_hash_payload(
            {
                "workflow_id": benchmark_payload.get("workflow_id", ""),
                "decision_state": decision_state,
                "rubric_outcome": rubric_outcome,
                "closure_state": closure_state,
                "repeatability_state": repeatability_state,
                "promotion_readiness_state": promotion_readiness_state,
                "successor_bundle_state": successor_bundle_state,
                "next_operator_action": next_operator_action,
            }
        )
        decision_packet_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_DECISION_PACKET_SCHEMA_NAME,
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_DECISION_PACKET_SCHEMA_VERSION
            ),
            "decision_signature": decision_signature,
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "workflow_name": str(benchmark_payload.get("workflow_name", "") or ""),
            "directive_file_path": str(
                directive_payload.get("directive_file_path", "") or ""
            ),
            "selected_path_id": "local",
            "allowed_bounded_path_set": allowed_bounded_path_set,
            "decision_state": decision_state,
            "decision_label": decision_label_map[decision_state],
            "rubric_outcome": rubric_outcome,
            "benchmark_closure_state": closure_state,
            "repeatability_state": repeatability_state,
            "promotion_readiness_state": promotion_readiness_state,
            "successor_readiness_bundle_state": successor_bundle_state,
            "decision_summary": decision_summary,
            "supporting_evidence_summary": " ".join(supporting_evidence_items),
            "blocking_evidence_summary": " ".join(blocking_evidence_items),
            "exact_final_blocker": exact_final_blocker,
            "next_operator_action": next_operator_action,
            "what_would_change_the_decision": what_would_change_the_decision,
            "review_gate_required": review_gate_required,
            "advisory_only": True,
            "non_authoritative_note": (
                "This decision packet is advisory only, does not authorize policy change, and does not authorize automatic promotion."
            ),
        }
        decision_packet_history_payload = {
            "schema_name": (
                CONTROLLER_REAL_WORK_BENCHMARK_DECISION_PACKET_HISTORY_SCHEMA_NAME
            ),
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_DECISION_PACKET_HISTORY_SCHEMA_VERSION
            ),
            "entry_count": 1,
            "entries": [
                {
                    "recorded_at": _now(),
                    "decision_signature": decision_signature,
                    "decision_state": decision_state,
                    "promotion_readiness_state": promotion_readiness_state,
                    "successor_readiness_bundle_state": successor_bundle_state,
                    "next_operator_action": next_operator_action,
                }
            ],
            "advisory_only": True,
            "non_authoritative_note": (
                "This decision history records the current bounded rc48 posture only and does not authorize policy change."
            ),
        }
        promotion_decision_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_PROMOTION_DECISION_SCHEMA_NAME,
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_PROMOTION_DECISION_SCHEMA_VERSION
            ),
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "selected_path_id": "local",
            "allowed_bounded_path_set": allowed_bounded_path_set,
            "promotion_decision": decision_state,
            "promotion_decision_label": decision_label_map[decision_state],
            "promotion_decision_summary": promotion_decision_summary,
            "supporting_evidence_rows": [
                {"summary": item} for item in supporting_evidence_items
            ],
            "blocking_evidence_rows": [{"summary": item} for item in blocking_evidence_items],
            "why_not_stronger_summary": why_not_stronger_summary,
            "advisory_only": True,
            "non_authoritative_note": (
                "This promotion decision is a review-gated operator aid only, does not authorize policy change, and does not authorize automatic promotion."
            ),
        }
        review_gate_packet_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_REVIEW_GATE_PACKET_SCHEMA_NAME,
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_REVIEW_GATE_PACKET_SCHEMA_VERSION
            ),
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "selected_path_id": "local",
            "allowed_bounded_path_set": allowed_bounded_path_set,
            "review_gate_status": (
                "review_required_for_promotion" if review_gate_required else "no_review_gate_recorded"
            ),
            "review_gate_label": (
                "Review required before promotion"
                if review_gate_required
                else "No review gate recorded"
            ),
            "review_gate_summary": (
                "The bundle is ready for human review now, but promotion remains explicitly gated because benchmark evidence is support-only and authority remains local."
                if review_gate_required
                else "No review gate is recorded."
            ),
            "what_is_ready_now": (
                "The repeatable readiness bundle, rebuilt handoff evidence, and packaged archive evidence are ready for human review."
            ),
            "what_still_requires_review": exact_final_blocker,
            "what_reviewer_should_inspect_first": (
                "Inspect promotion-readiness, unresolved-bundle, and output-inventory artifacts first."
            ),
            "best_artifacts_to_review_first": review_first_artifact_paths,
            "supporting_artifacts_after_first_review": secondary_artifact_paths,
            "advisory_only": True,
            "non_authoritative_note": (
                "This review-gate packet clarifies what to inspect next and does not authorize policy change or automatic promotion."
            ),
        }
        final_blocker_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_FINAL_BLOCKER_SCHEMA_NAME,
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_FINAL_BLOCKER_SCHEMA_VERSION
            ),
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "selected_path_id": "local",
            "allowed_bounded_path_set": allowed_bounded_path_set,
            "final_blocker_state": final_blocker_state,
            "final_blocker_label": final_blocker_state.replace("_", " "),
            "successor_readiness_bundle_state": successor_bundle_state,
            "exact_final_blocker": exact_final_blocker,
            "final_blocker_summary": (
                "The last remaining blocker is human confirmation of the rebuilt successor readiness bundle."
                if final_blocker_state == "review_confirmation_required"
                else exact_final_blocker
            ),
            "blocking_evidence_summary": " ".join(blocking_evidence_items),
            "advisory_only": True,
            "non_authoritative_note": (
                "This final-blocker record clarifies the remaining bounded blocker and does not authorize policy change or promotion."
            ),
        }
        decision_rationale_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_DECISION_RATIONALE_SCHEMA_NAME,
            "schema_version": (
                CONTROLLER_REAL_WORK_BENCHMARK_DECISION_RATIONALE_SCHEMA_VERSION
            ),
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "selected_path_id": "local",
            "allowed_bounded_path_set": allowed_bounded_path_set,
            "decision_state": decision_state,
            "decision_rationale_label": decision_label_map[decision_state],
            "decision_rationale_summary": (
                f"{decision_label_map[decision_state]} is justified because "
                f"{decision_summary[0].lower() + decision_summary[1:] if decision_summary else 'the current evidence supports it.'}"
            ),
            "why_not_stronger_decision_summary": why_not_stronger_summary,
            "supporting_evidence_summary": " ".join(supporting_evidence_items),
            "blocking_evidence_summary": " ".join(blocking_evidence_items),
            "delta_context_summary": str(
                delta_payload.get("delta_summary", "")
                or "No rc46-to-rc47 delta context is recorded."
            ),
            "advisory_only": True,
            "non_authoritative_note": (
                "This decision rationale is operator support only and does not authorize policy change or automatic promotion."
            ),
        }
        next_action_payload = {
            "schema_name": CONTROLLER_REAL_WORK_BENCHMARK_NEXT_ACTION_SCHEMA_NAME,
            "schema_version": CONTROLLER_REAL_WORK_BENCHMARK_NEXT_ACTION_SCHEMA_VERSION,
            "workflow_id": str(benchmark_payload.get("workflow_id", "") or ""),
            "selected_path_id": "local",
            "allowed_bounded_path_set": allowed_bounded_path_set,
            "next_operator_action": next_operator_action,
            "next_action_label": next_action_label_map[next_operator_action],
            "next_action_summary": (
                "Review the rebuilt successor bundle now and confirm whether the preserved readiness packet is sufficient for review-gated promotion."
                if next_operator_action == "review_now"
                else "Hold the bundle until the remaining blocker is resolved more decisively."
                if next_operator_action == "hold_until_specific_evidence"
                else "Refresh the bundle before revisiting promotion."
                if next_operator_action == "defer_and_refresh_bundle"
                else "Do not take a promotion action from the current packet."
            ),
            "what_to_review_first": (
                "Start with the promotion-readiness packet, unresolved-bundle packet, and output inventory."
            ),
            "what_would_change_the_decision": what_would_change_the_decision,
            "advisory_only": True,
            "non_authoritative_note": (
                "This next-action record is guidance only and does not authorize policy change, automatic promotion, or automatic execution."
            ),
        }

        updated_benchmark_payload = dict(benchmark_payload)
        updated_benchmark_payload.update(
            {
                "benchmark_decision_state": decision_state,
                "promotion_decision": decision_state,
                "next_operator_action": next_operator_action,
                "final_blocker_state": final_blocker_state,
                "latest_decision_signature": decision_signature,
                "future_execution_note": (
                    "Rc48 preserves the selected benchmark lane and converts the repeatability / closure evidence into an explicit operator decision packet without broadening authority."
                ),
            }
        )

        save_controller_real_work_benchmark(
            updated_benchmark_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_decision_packet(
            decision_packet_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_decision_packet_history(
            decision_packet_history_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_promotion_decision(
            promotion_decision_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_review_gate_packet(
            review_gate_packet_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_final_blocker(
            final_blocker_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_decision_rationale(
            decision_rationale_payload,
            root=self.operator_root,
        )
        save_controller_real_work_benchmark_next_action(
            next_action_payload,
            root=self.operator_root,
        )
        return {
            "controller_real_work_benchmark": updated_benchmark_payload,
            "controller_real_work_benchmark_decision_packet": decision_packet_payload,
            "controller_real_work_benchmark_decision_packet_history": (
                decision_packet_history_payload
            ),
            "controller_real_work_benchmark_promotion_decision": (
                promotion_decision_payload
            ),
            "controller_real_work_benchmark_review_gate_packet": (
                review_gate_packet_payload
            ),
            "controller_real_work_benchmark_final_blocker": (
                final_blocker_payload
            ),
            "controller_real_work_benchmark_decision_rationale": (
                decision_rationale_payload
            ),
            "controller_real_work_benchmark_next_action": next_action_payload,
            "controller_real_work_benchmark_decision_packet_path": str(
                controller_real_work_benchmark_decision_packet_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_decision_packet_history_path": str(
                controller_real_work_benchmark_decision_packet_history_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_promotion_decision_path": str(
                controller_real_work_benchmark_promotion_decision_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_review_gate_packet_path": str(
                controller_real_work_benchmark_review_gate_packet_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_final_blocker_path": str(
                controller_real_work_benchmark_final_blocker_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_decision_rationale_path": str(
                controller_real_work_benchmark_decision_rationale_path(
                    root=self.operator_root
                )
            ),
            "controller_real_work_benchmark_next_action_path": str(
                controller_real_work_benchmark_next_action_path(
                    root=self.operator_root
                )
            ),
        }

    def _save_real_work_benchmark_review_action_views(
        self,
        *,
        operator_snapshot: dict[str, Any],
    ) -> dict[str, Any]:
        benchmark_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark", {})
        )
        directive_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_directive", {})
        )
        output_inventory_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_output_inventory", {})
        )
        promotion_readiness_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_promotion_readiness", {})
        )
        unresolved_bundle_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_unresolved_bundle", {})
        )
        decision_packet_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_decision_packet", {})
        )
        promotion_decision_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_promotion_decision", {})
        )
        review_gate_packet_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_review_gate_packet", {})
        )
        final_blocker_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_final_blocker", {})
        )
        next_action_payload = dict(
            operator_snapshot.get("controller_real_work_benchmark_next_action", {})
        )
        generic_review_decision_payload = dict(
            operator_snapshot.get("operator_review_decision", {})
        )
        generic_review_resolution_payload = dict(
            operator_snapshot.get("operator_review_resolution", {})
        )
        generic_review_action_execution_payload = dict(
            operator_snapshot.get("operator_review_action_execution", {})
        )

        allowed_bounded_path_set = [
            "local",
            "librarian",
            "verifier",
            "sequential_librarian_then_verifier",
        ]
        workflow_id = str(benchmark_payload.get("workflow_id", "") or "")
        workflow_name = str(benchmark_payload.get("workflow_name", "") or "")
        directive_file_path = str(
            directive_payload.get("directive_file_path", "") or ""
        )

        review_template_path = _real_work_benchmark_review_decision_template_path(
            self.package_root
        )
        default_review_template = _default_real_work_benchmark_review_decision_template(
            workflow_id=workflow_id,
            workflow_name=workflow_name,
            directive_file_path=directive_file_path,
        )
        template_exists_before_rc49 = review_template_path.exists()
        raw_template_payload = _load_json_file_if_exists(review_template_path)
        review_template_payload = dict(default_review_template)
        if isinstance(raw_template_payload, Mapping):
            for key, value in raw_template_payload.items():
                if key in {
                    "schema_name",
                    "schema_version",
                    "workflow_id",
                    "workflow_name",
                    "directive_file_path",
                    "allowed_outcome_states",
                }:
                    continue
                review_template_payload[key] = value
        template_created_now = False
        template_write_error = ""
        if not template_exists_before_rc49:
            try:
                review_template_path.parent.mkdir(parents=True, exist_ok=True)
                review_template_path.write_text(
                    json.dumps(review_template_payload, indent=2) + "\n",
                    encoding="utf-8",
                )
                template_created_now = True
            except OSError as exc:
                template_write_error = str(exc)

        allowed_outcome_states = {
            "promotion_confirmed_with_review_gate",
            "hold_confirmed_with_review_gate",
            "defer_confirmed",
            "blocked_review_outcome",
            "awaiting_operator_confirmation",
        }
        confirmed_outcome_states = {
            "promotion_confirmed_with_review_gate",
            "hold_confirmed_with_review_gate",
            "defer_confirmed",
            "blocked_review_outcome",
        }
        template_outcome_state = str(
            review_template_payload.get("promotion_outcome_state", "")
            or "awaiting_operator_confirmation"
        ).strip()
        if template_outcome_state not in allowed_outcome_states:
            template_outcome_state = "awaiting_operator_confirmation"
