    def _workspace_artifact_groups(self, snapshot: dict[str, Any]) -> dict[str, list[dict[str, Any]]]:
        workspace_root = str(snapshot.get("workspace_root", "")).strip()
        if not workspace_root:
            return {category: [] for category in WORKSPACE_ARTIFACT_CATEGORIES}
        workspace_root_path = Path(workspace_root)
        index = dict(snapshot.get("artifact_index", {}))
        records = []
        for item in list(index.get("artifacts", [])):
            relative_path = str(item.get("relative_path", "")).strip()
            if not relative_path:
                continue
            records.append(
                {
                    "relative_path": relative_path,
                    "category": str(item.get("category", "")).strip() or _slug(Path(relative_path).parts[0], fallback="other"),
                }
            )
        if not records:
            for path in sorted(workspace_root_path.rglob("*")):
                if not path.is_file():
                    continue
                relative_path = path.relative_to(workspace_root_path).as_posix()
                category = Path(relative_path).parts[0] if Path(relative_path).parts else "other"
                records.append({"relative_path": relative_path, "category": category})

        groups: dict[str, list[dict[str, Any]]] = {category: [] for category in WORKSPACE_ARTIFACT_CATEGORIES}
        for record in records:
            category = str(record.get("category", "")).strip()
            if category not in groups:
                continue
            relative_path = str(record.get("relative_path", "")).strip()
            absolute_path = workspace_root_path / Path(relative_path)
            if not absolute_path.exists() or not absolute_path.is_file():
                continue
            stat = absolute_path.stat()
            groups[category].append(
                {
                    "category": category,
                    "relative_path": relative_path,
                    "absolute_path": str(absolute_path),
                    "modified_at": _format_timestamp(datetime.fromtimestamp(stat.st_mtime, tz=timezone.utc).isoformat()),
                    "size_display": _format_bytes(stat.st_size),
                    "size_bytes": int(stat.st_size),
                    "is_key_artifact": relative_path in KEY_WORKSPACE_ARTIFACTS,
                    "preview_href": self._preview_link_for_path(str(absolute_path)),
                }
            )
        for category in groups:
            groups[category].sort(
                key=lambda item: (
                    0 if item.get("is_key_artifact") else 1,
                    str(item.get("relative_path", "")).lower(),
                )
            )
        return groups

    def _display_artifact_hint(
        self,
        path: str,
        *,
        snapshot: dict[str, Any] | None = None,
    ) -> str:
        normalized = self._remap_packaged_path(str(path or "").strip())
        if not normalized:
            return "<none>"
        candidate = Path(normalized)
        try:
            candidate_resolved = candidate.resolve()
        except OSError:
            candidate_resolved = candidate
        roots: list[Path] = []
        if snapshot:
            workspace_root = str(snapshot.get("workspace_root", "")).strip()
            if workspace_root:
                roots.append(Path(workspace_root))
        roots.extend(
            [
                self.package_root,
                self.operator_root,
                self.state_root,
                self.directive_root,
                self.evidence_root,
            ]
        )
        for root in roots:
            try:
                relative = candidate_resolved.relative_to(Path(root).resolve())
            except ValueError:
                continue
            return relative.as_posix()
        return candidate.name or normalized

    def _materialize_demo_reviewable_outputs(
        self,
        *,
        context: Mapping[str, Any],
    ) -> list[dict[str, Any]]:
        artifact_dir = self.state_root / "demo_reviewable_outputs"
        artifact_dir.mkdir(parents=True, exist_ok=True)
        scenario_id = str(context.get("scenario_id", "") or "").strip()
        scenario_name = str(context.get("scenario_name", "") or "").strip()
        directive_id = str(context.get("directive_id", "") or "").strip()
        workspace_id = str(context.get("workspace_id", "") or "").strip()
        workspace_root = str(context.get("workspace_root", "") or "").strip()
        supporting_artifact_paths = [
            str(item).strip()
            for item in list(context.get("supporting_artifact_paths", []) or [])
            if str(item).strip()
        ]
        summary_path = artifact_dir / "demo_latest_summary_artifact_latest.json"
        implementation_path = artifact_dir / "demo_implementation_summary_latest.json"
        artifact_index_path = artifact_dir / "demo_workspace_artifact_index_latest.json"
        summary_payload = {
            "schema_name": "ControllerDemoLatestSummaryArtifact",
            "schema_version": "controller_demo_latest_summary_artifact_v1",
            "generated_at": _now(),
            "scenario_id": scenario_id,
            "scenario_name": scenario_name,
            "directive_id": directive_id,
            "workspace_id": workspace_id,
            "workspace_root": workspace_root,
            "artifact_kind": "latest_summary_artifact",
            "artifact_origin": "generated_from_current_bounded_operator_state",
            "advisory_only": True,
            "recommended_path_label": str(
                context.get("current_recommended_path_label", "") or "<none>"
            ),
            "suggested_next_operator_action_label": str(
                context.get("suggested_next_operator_action_label", "") or "<none>"
            ),
            "action_readiness_label": str(
                context.get("action_readiness_label", "") or "<none>"
            ),
            "guided_next_destination_label": str(
                context.get("guided_next_destination_label", "") or "<none>"
            ),
            "current_step_label": str(context.get("current_step_label", "") or "<none>"),
            "current_step_summary": str(
                context.get("current_step_summary", "") or "<none>"
            ),
            "next_step_label": str(context.get("next_step_label", "") or "<none>"),
            "next_step_summary": str(context.get("next_step_summary", "") or "<none>"),
            "governance_summary_label": str(
                context.get("governance_summary_label", "") or "<none>"
            ),
            "governance_summary_reason": str(
                context.get("governance_summary_reason", "") or "<none>"
            ),
            "governance_trend_label": str(
                context.get("governance_trend_label", "") or "<none>"
            ),
            "demo_run_readiness_label": str(
                context.get("demo_run_readiness_label", "") or "<none>"
            ),
            "no_strong_recommendation": bool(
                context.get("no_strong_recommendation", False)
            ),
            "summary_text": str(
                context.get("reviewable_summary_text", "")
                or "This reviewable summary captures the current bounded operator state without executing new mission work."
            ),
            "supporting_artifact_paths": supporting_artifact_paths,
        }
        _write_json_file(summary_path, summary_payload)
        implementation_payload = {
            "schema_name": "ControllerDemoImplementationSummaryArtifact",
            "schema_version": "controller_demo_implementation_summary_artifact_v1",
            "generated_at": _now(),
            "scenario_id": scenario_id,
            "scenario_name": scenario_name,
            "directive_id": directive_id,
            "workspace_id": workspace_id,
            "workspace_root": workspace_root,
            "artifact_kind": "implementation_summary",
            "artifact_origin": "generated_from_current_bounded_operator_state",
            "advisory_only": True,
            "implementation_summary": str(
                context.get("implementation_summary_text", "")
                or "This packaged walkthrough generated reviewable demo artifacts from persisted recommendation, readiness, handoff, and flow state without widening authority."
            ),
            "allowed_path_ids": list(context.get("allowed_path_ids", []) or []),
            "system_supported_path_ids": list(
                context.get("system_supported_path_ids", []) or []
            ),
            "current_demo_run_status": str(
                context.get("current_demo_run_status", "") or "<none>"
            ),
            "what_this_output_set_proves": str(
                context.get("what_this_output_set_proves", "")
                or "NOVALI can generate reviewable bounded demo artifacts from current packaged state even when the governance posture remains explicit and conservative."
            ),
            "what_remains_unresolved": str(
                context.get("what_remains_unresolved", "")
                or "Any unresolved recommendation or evidence posture remains visible instead of being compressed into a fake completion claim."
            ),
            "supporting_artifact_paths": supporting_artifact_paths,
        }
        _write_json_file(implementation_path, implementation_payload)
        index_items: list[dict[str, Any]] = []
        for category, label, candidate_path, source_kind in (
            (
                "demo_outputs",
                "Latest summary artifact",
                str(summary_path),
                "generated_from_current_bounded_operator_state",
            ),
            (
                "demo_outputs",
                "Implementation summary",
                str(implementation_path),
                "generated_from_current_bounded_operator_state",
            ),
            (
                "demo_outputs",
                "Workspace artifact index",
                str(artifact_index_path),
                "generated_from_current_bounded_operator_state",
            ),
        ):
            index_items.append(
                {
                    "category": category,
                    "label": label,
                    "path": candidate_path,
                    "relative_path": self._display_artifact_hint(candidate_path),
                    "source_kind": source_kind,
                    "reviewable_now": True,
                    "produced_by_packaged_run": True,
                }
            )
        for artifact_path in supporting_artifact_paths:
            candidate = Path(artifact_path)
            if not candidate.exists() or not candidate.is_file():
                continue
            index_items.append(
                {
                    "category": "supporting_inputs",
                    "label": candidate.name,
                    "path": artifact_path,
                    "relative_path": self._display_artifact_hint(artifact_path),
                    "source_kind": "existing_supporting_artifact",
                    "reviewable_now": True,
                    "produced_by_packaged_run": False,
                }
            )
        category_counts: dict[str, int] = {}
        for item in index_items:
            category = str(item.get("category", "") or "other")
            category_counts[category] = int(category_counts.get(category, 0) or 0) + 1
        artifact_index_payload = {
            "schema_name": "ControllerDemoWorkspaceArtifactIndex",
            "schema_version": "controller_demo_workspace_artifact_index_v1",
            "generated_at": _now(),
            "scenario_id": scenario_id,
            "scenario_name": scenario_name,
            "directive_id": directive_id,
            "workspace_id": workspace_id,
            "workspace_root": workspace_root,
            "artifact_root": str(artifact_dir),
            "artifact_count": len(index_items),
            "artifacts": index_items,
            "category_counts": category_counts,
            "advisory_only": True,
        }
        _write_json_file(artifact_index_path, artifact_index_payload)
        return [
            {
                "label": "Latest summary artifact",
                "path": str(summary_path),
                "required": True,
                "present": True,
                "reviewable_now": True,
                "output_origin": "generated_from_current_bounded_operator_state",
                "produced_by_packaged_run": True,
                "reason_summary": "Generated from the current bounded operator state so the packaged walkthrough has a reviewable summary artifact.",
            },
            {
                "label": "Implementation summary",
                "path": str(implementation_path),
                "required": True,
                "present": True,
                "reviewable_now": True,
                "output_origin": "generated_from_current_bounded_operator_state",
                "produced_by_packaged_run": True,
                "reason_summary": "Generated from the current bounded operator state so the packaged walkthrough has a reviewable implementation summary.",
            },
            {
                "label": "Workspace artifact index",
                "path": str(artifact_index_path),
                "required": True,
                "present": True,
                "reviewable_now": True,
                "output_origin": "generated_from_current_bounded_operator_state",
                "produced_by_packaged_run": True,
                "reason_summary": "Generated from current packaged-state artifacts so the operator can review what the walkthrough surfaced.",
            },
        ]

    def _showcase_artifact_items(
        self,
        snapshot: dict[str, Any],
        *,
        limit: int = 6,
    ) -> list[dict[str, str]]:
        items: list[dict[str, str]] = []
        seen: set[str] = set()
        created_paths = {
            str(path).strip() for path in list(snapshot.get("newly_created_paths", [])) if str(path).strip()
        }

        def add_item(path: str, label: str, detail: str, *, tone: str = "info") -> None:
            normalized = str(path or "").strip()
            if not normalized or normalized in seen or len(items) >= limit:
                return
            remapped = self._remap_packaged_path(normalized)
            candidate = Path(remapped)
            if not candidate.exists() or not candidate.is_file():
                return
            seen.add(normalized)
            items.append(
                {
                    "label": label,
                    "value": self._display_artifact_hint(remapped, snapshot=snapshot),
                    "detail": detail,
                    "preview_href": self._preview_link_for_path(remapped),
                    "tone": tone,
                }
            )

        for field_name, label, detail in SHOWCASE_ARTIFACT_PRIORITY:
            add_item(
                str(snapshot.get(field_name, "") or ""),
                label,
                detail,
                tone="info",
            )

        for path in list(snapshot.get("newly_created_paths", [])):
            add_item(
                str(path),
                "New workspace output",
                "Created during the latest bounded result.",
                tone="success",
            )

        for path in list(snapshot.get("output_artifact_paths", [])):
            normalized = str(path or "").strip()
            add_item(
                normalized,
                "Tracked output",
                (
                    "Created during the latest bounded result."
                    if normalized in created_paths
                    else "Recorded in the latest bounded output set."
                ),
                tone="info",
            )

        if not items and str(self.directive_file).strip():
            add_item(
                self.directive_file,
                "Directive core",
                "Formal directive wrapper currently loaded by the browser-first operator flow.",
                tone="info",
            )

        return items

    def _render_showcase_artifact_cards(
        self,
        snapshot: dict[str, Any],
        *,
        limit: int = 6,
    ) -> str:
        items = self._showcase_artifact_items(snapshot, limit=limit)
        if not items:
            return (
                "<p class='muted'>No important outputs are recorded yet. "
                "Once bootstrap or governed work writes bounded artifacts, the most useful ones will surface here.</p>"
            )
        return "".join(
            _render_artifact_story_card(
                str(item.get("label", "")),
                str(item.get("value", "")),
                detail=str(item.get("detail", "")),
                tone=str(item.get("tone", "")),
                preview_href=str(item.get("preview_href", "")),
            )
            for item in items
        )

    def _render_recent_runtime_event_cards(
        self,
        snapshot: dict[str, Any],
        *,
        limit: int = 4,
    ) -> str:
        runtime_events = list(snapshot.get("runtime_events", []))
        if not runtime_events:
            return "<p class='muted'>No structured runtime events are recorded yet.</p>"
        cards: list[str] = []
        for event in reversed(runtime_events[-limit:]):
            event_type = str(event.get("event_type", "")).strip()
            event_title = EVENT_LABELS.get(event_type, event_type or "runtime event")
            detail = _first_non_empty_text(
                event.get("reason", ""),
                event.get("status", ""),
                event.get("summary_artifact_path", ""),
                fallback="Structured runtime event recorded.",
            )
            timestamp = _format_timestamp(event.get("timestamp", ""))
            cards.append(
                _render_story_card(
                    timestamp,
                    event_title,
                    detail=detail,
                    tone=_status_tone(event_title),
                )
            )
        return "".join(cards)

    def _preview_allowed_roots(self, snapshot: dict[str, Any]) -> list[Path]:
        roots = [
            self.package_root,
            self.operator_root,
            self.state_root,
            self.evidence_root,
            self.directive_root,
        ]
        workspace_root = str(snapshot.get("workspace_root", "")).strip()
        if workspace_root:
            roots.append(Path(workspace_root))
        unique: list[Path] = []
        seen: set[str] = set()
        for root in roots:
            normalized = _normalize_path(root)
            if normalized in seen:
                continue
            seen.add(normalized)
            unique.append(Path(normalized))
        return unique

    def _observability_snapshot(self) -> dict[str, Any]:
        dashboard = self.current_dashboard_snapshot()
        operator_snapshot = self.current_operator_snapshot()
        return self._build_observability_snapshot(
            dashboard=dashboard,
            operator_snapshot=operator_snapshot,
        )

    def _resolve_preview_path(self, requested_path: str) -> Path | None:
        normalized = str(requested_path or "").strip()
        if not normalized:
            return None
        try:
            candidate = Path(normalized).resolve()
        except OSError:
            return None
        if candidate.suffix.lower() not in PREVIEWABLE_SUFFIXES:
            return None
        if not candidate.exists() or not candidate.is_file():
            return None
        snapshot = self._observability_snapshot()
        if not any(_is_under_path(candidate, root) for root in self._preview_allowed_roots(snapshot)):
            return None
        return candidate

