    def save_operator_run_preset_selection(
        self,
        form_data: dict[str, str],
    ) -> dict[str, Any]:
        preset_id = str(
            form_data.get("preset_id", DEFAULT_OPERATOR_RUN_PRESET_ID)
        ).strip() or DEFAULT_OPERATOR_RUN_PRESET_ID
        preset_payload = save_operator_run_preset(preset_id, root=self.operator_root)
        effective_policy = dict(preset_payload.get("effective_trusted_source_policy", {}))
        normalized_policy = save_trusted_source_operator_policy(
            effective_policy,
            root=self.operator_root,
        )
        preset_defaults = self.operator_run_preset_defaults()
        return {
            "ok": True,
            "headline": "Operator run preset saved.",
            "details": [
                "Active preset: " + str(preset_payload.get("preset_label", preset_id)),
                "Preset state: " + str(preset_payload.get("preset_state", "")),
                "Trusted-source policy state: " + str(normalized_policy.get("policy_state", "")),
                "Governed execution recommendation: "
                + str(preset_defaults.get("governed_execution_mode", ""))
                + " / max cycles "
                + str(preset_defaults.get("governed_max_cycles_per_invocation", "")),
                "Advanced controls page: " + str(preset_defaults.get("advanced_controls_route", "/settings")),
                "Preset artifact: " + str(self.current_operator_snapshot().get("operator_run_preset_path", "")),
            ],
        }

