        workspace_id = "workspace_advanced_successor_v3_live_c"
        workspace_root = self.package_root / "novali-active_workspace" / workspace_id
        packaged_evidence_root = (
            self.package_root
            / "runtime_data"
            / "acceptance_evidence"
            / "trusted_source_demo_reference_inventory"
        )

        def _preferred_path(primary: Path, fallback_relative: str) -> Path:
            fallback = packaged_evidence_root / Path(fallback_relative)
            if primary.exists():
                return primary
            if fallback.exists():
                return fallback
            return primary

        artifacts_root = workspace_root / "artifacts"
        docs_root = workspace_root / "docs"
        src_root = workspace_root / "src" / "successor_shell"
        tests_root = workspace_root / "tests"
