        def _normalize_paths(*groups: Any) -> list[str]:
            normalized: list[str] = []
            seen: set[str] = set()
            for group in groups:
                values = group if isinstance(group, (list, tuple, set)) else [group]
                for value in values:
                    text = str(value or "").strip()
                    if not text:
                        continue
                    path_text = self._remap_packaged_path(text)
                    if not path_text or path_text in seen:
                        continue
                    seen.add(path_text)
                    normalized.append(path_text)
            return normalized

