    def save_runtime_policy(self, form_data: dict[str, str]) -> dict[str, Any]:
        try:
            runtime_payload = self._runtime_payload_from_form(form_data)
            envelope_payload = self._envelope_payload_from_form(form_data)
        except Exception as exc:
            return {
                "ok": False,
                "headline": "Runtime policy parsing failed.",
                "details": [str(exc)],
            }

        operator_snapshot = self.current_operator_snapshot()
        runtime_errors, normalized_runtime, _ = validate_runtime_constraints(
            runtime_payload,
            package_root=self.package_root,
            operator_root=self.operator_root,
        )
        envelope_errors, normalized_envelope, _ = validate_operator_runtime_envelope_spec(
            envelope_payload,
            runtime_constraints=normalized_runtime,
            trusted_source_bindings=load_trusted_source_bindings_or_default(
                root=self.operator_root,
                package_root=self.package_root,
            ),
            backend_probe=dict(operator_snapshot.get("runtime_backend_probe", {})),
            enforce_backend_availability=True,
        )
        errors = list(runtime_errors) + list(envelope_errors)
        if errors:
            attempted_defaults = self._runtime_form_defaults_from_payloads(
                runtime_payload=normalized_runtime or runtime_payload,
                runtime_envelope=normalized_envelope or envelope_payload,
            )
            details = list(errors)
            if (
                self.is_packaged_handoff_context()
                and str(form_data.get("backend_kind", "")).strip() == BACKEND_LOCAL_DOCKER
                and any(
                    "selected runtime backend is unavailable: local_docker" in str(item)
                    for item in errors
                )
            ):
                details.append(
                    "Standalone package hint: keep backend local_guarded in the packaged browser UI. "
                    "The current container already provides the Docker execution envelope, so nested "
                    "local_docker launches are not available in this slice."
                )
            details.append("Authoritative runtime policy remains unchanged because the requested values were not saved.")
            return {
                "ok": False,
                "headline": "Runtime policy was not saved.",
                "details": details,
                "runtime_form_override": attempted_defaults,
                "attempted_runtime_summary": self._render_runtime_policy_preview(attempted_defaults),
            }

        save_runtime_constraints(normalized_runtime, root=self.operator_root)
        save_runtime_envelope_spec(normalized_envelope, root=self.operator_root)
        self.profile["recent_runtime_policy_directive_file"] = str(
            self.directive_file
        ).strip()
        self._persist_profile()
        workspace_policy = dict(normalized_runtime.get("workspace_policy", {}))
        return {
            "ok": True,
            "headline": "Runtime policy saved and applied for future launches.",
            "details": [
                f"Execution profile: {normalized_runtime.get('execution_profile', '')}",
                (
                    "Governed execution controller: "
                    f"{dict(normalized_runtime.get('governed_execution', {})).get('mode', '')} / "
                    f"max_cycles={dict(normalized_runtime.get('governed_execution', {})).get('max_cycles_per_invocation', '')} / "
                    f"total_cycle_cap={dict(normalized_runtime.get('governed_execution', {})).get('max_total_cycles', '')}"
                ),
                (
                    "Active workspace: "
                    f"{workspace_policy.get('workspace_id', '')} -> {workspace_policy.get('workspace_root', '')}"
                    if str(workspace_policy.get("workspace_root", "")).strip()
                    else "Active workspace: <not required for this profile>"
                ),
                f"Runtime constraints source: {operator_runtime_constraints_path(self.operator_root)}",
                f"Runtime envelope source: {operator_runtime_envelope_spec_path(self.operator_root)}",
            ],
        }

    def save_long_run_policy(self, payload: Mapping[str, Any]) -> dict[str, Any]:
        runtime_defaults = self.runtime_form_defaults()
        state_snapshot = self.shell_long_run_state_payload()
        long_run = dict(state_snapshot.get("long_run", {}))
        effective_policy = dict(state_snapshot.get("effective_policy", {}))
        continuation_strategy = str(
            payload.get(
                "continuation_strategy",
                effective_policy.get("continuation_strategy", "single_step"),
            )
        ).strip() or "single_step"
        if continuation_strategy not in {"single_step", "until_bounded_stop"}:
            return {
                "ok": False,
                "headline": "Long-run policy was not saved.",
                "message": "Long-run policy was not saved.",
                "details": [
                    "Continuation strategy must be single_step or until_bounded_stop.",
                ],
                "effective_policy": effective_policy,
                "state": state_snapshot,
            }
        max_cycles_per_invocation = str(
            payload.get(
                "max_cycles_per_invocation",
                effective_policy.get("max_cycles_per_invocation", runtime_defaults.get("max_cycles_per_invocation", "1")),
            )
        ).strip()
        max_total_cycles = str(
            payload.get(
                "max_total_cycles",
                effective_policy.get("max_total_cycles", runtime_defaults.get("max_total_cycles", "1")),
            )
        ).strip()
        if continuation_strategy == "single_step" and max_cycles_per_invocation not in {"", "1"}:
            return {
                "ok": False,
                "headline": "Long-run policy was not saved.",
                "message": "Long-run policy was not saved.",
                "details": [
                    "Single-step continuation requires max_cycles_per_invocation = 1.",
                ],
                "effective_policy": effective_policy,
                "state": state_snapshot,
            }
        workspace_id = str(
            long_run.get("workspace_id")
            or dict(state_snapshot.get("session", {})).get("workspace_id")
            or runtime_defaults.get("workspace_id", "")
        ).strip()
        if not workspace_id:
            return {
                "ok": False,
                "headline": "Long-run policy was not saved.",
                "message": "Long-run policy was not saved.",
                "details": [
                    "A bounded workspace must be materialized before long-run policy can be edited from this surface.",
                ],
                "effective_policy": effective_policy,
                "state": state_snapshot,
            }
        governed_execution_mode = (
            GOVERNED_EXECUTION_MODE_MULTI_CYCLE
            if continuation_strategy == "until_bounded_stop"
            else GOVERNED_EXECUTION_MODE_SINGLE_CYCLE
        )
        result = self.save_runtime_policy(
            {
                "execution_profile": EXECUTION_PROFILE_BOUNDED_ACTIVE_WORKSPACE_CODING,
                "workspace_id": workspace_id,
                "max_memory_mb": str(runtime_defaults.get("max_memory_mb", "")),
                "max_python_threads": str(runtime_defaults.get("max_python_threads", "")),
                "max_child_processes": str(runtime_defaults.get("max_child_processes", "")),
                "subprocess_mode": str(runtime_defaults.get("subprocess_mode", "")),
                "session_time_limit_seconds": str(
                    runtime_defaults.get("session_time_limit_seconds", "")
                ),
                "governed_execution_mode": governed_execution_mode,
                "max_cycles_per_invocation": max_cycles_per_invocation,
                "max_total_cycles": max_total_cycles,
                "backend_kind": str(runtime_defaults.get("backend_kind", BACKEND_LOCAL_GUARDED)),
                "cpu_limit_cpus": str(runtime_defaults.get("cpu_limit_cpus", "")),
                "docker_image": str(runtime_defaults.get("docker_image", "")),
                "network_policy_intent": str(
                    runtime_defaults.get("network_policy_intent", "deny_all")
                ),
            }
        )
        refreshed = self.shell_long_run_state_payload()
        if result.get("ok", False):
            event_path = str(self.shell_runtime_event_path()).strip()
            if event_path not in {"", "."}:
                try:
                    target = Path(event_path)
                    target.parent.mkdir(parents=True, exist_ok=True)
                    with target.open("a", encoding="utf-8") as handle:
                        handle.write(
                            json.dumps(
                                {
                                    "timestamp": _now(),
                                    "event_type": "continuation_policy_saved",
                                    "runtime_phase": "operator_policy",
                                    "message": (
                                        "Continuation policy saved: "
                                        f"{dict(refreshed.get('effective_policy', {})).get('continuation_strategy_label', 'Continue one bounded step')} "
                                        f"(max_total_cycles={dict(refreshed.get('effective_policy', {})).get('max_total_cycles', 0)}, "
                                        f"max_cycles_per_invocation={dict(refreshed.get('effective_policy', {})).get('max_cycles_per_invocation', 0)})."
                                    ),
                                    "workspace_id": str(dict(refreshed.get("long_run", {})).get("workspace_id", "")),
                                    "session_id": str(dict(refreshed.get("long_run", {})).get("session_id", "")),
                                    "artifact_path": str(
                                        operator_runtime_constraints_path(self.operator_root)
                                    ),
                                    "directive_id": _slug(
                                        Path(self.directive_file).stem,
                                        fallback="directive",
                                    ),
                                },
                                sort_keys=True,
                            )
                            + "\n"
                        )
                except OSError:
                    pass
        return {
            "ok": bool(result.get("ok", False)),
            "headline": str(result.get("headline", "")),
            "message": str(result.get("headline", "")),
            "details": list(result.get("details", [])),
            "effective_policy": dict(refreshed.get("effective_policy", {})),
            "state": refreshed,
        }

    def prepare_governed_execution_from_preset(
        self,
        *,
        directive_file: str = "",
    ) -> dict[str, Any]:
        directive_file = str(directive_file).strip()
        if directive_file:
            self.update_profile(directive_file=directive_file)
        runtime_defaults = self.runtime_form_defaults()
        preset_defaults = self.operator_run_preset_defaults()
        result = self.save_runtime_policy(
            {
                "execution_profile": str(
                    preset_defaults.get(
                        "governed_execution_profile",
                        EXECUTION_PROFILE_BOUNDED_ACTIVE_WORKSPACE_CODING,
                    )
                ),
                "workspace_id": str(runtime_defaults.get("workspace_id", "")),
                "max_memory_mb": str(runtime_defaults.get("max_memory_mb", "")),
                "max_python_threads": str(runtime_defaults.get("max_python_threads", "")),
                "max_child_processes": str(runtime_defaults.get("max_child_processes", "")),
                "subprocess_mode": str(runtime_defaults.get("subprocess_mode", "")),
                "session_time_limit_seconds": str(
                    runtime_defaults.get("session_time_limit_seconds", "")
                ),
                "governed_execution_mode": str(
                    preset_defaults.get(
                        "governed_execution_mode",
                        GOVERNED_EXECUTION_MODE_MULTI_CYCLE,
                    )
                ),
                "max_cycles_per_invocation": str(
                    preset_defaults.get("governed_max_cycles_per_invocation", "1")
                ),
                "max_total_cycles": str(
                    preset_defaults.get(
                        "governed_max_total_cycles",
                        runtime_defaults.get("max_total_cycles", "1"),
                    )
                ),
                "backend_kind": str(
                    runtime_defaults.get("backend_kind", BACKEND_LOCAL_GUARDED)
                ),
                "cpu_limit_cpus": str(runtime_defaults.get("cpu_limit_cpus", "")),
                "docker_image": str(runtime_defaults.get("docker_image", "")),
                "network_policy_intent": str(
                    runtime_defaults.get("network_policy_intent", "deny_all")
                ),
            }
        )
        governed_status = self.shell_governed_status_payload()
        details = list(result.get("details", []))
        if result.get("ok", False):
            if governed_status.get("can_launch", False):
                headline = "Governed runtime profile prepared."
                details.append(
                    "Landing-page governed execution can now use resume_existing + governed_execution."
                )
            else:
                headline = "Governed runtime profile restored."
                details.append(
                    str(governed_status.get("operator_next_action_detail", "")).strip()
                    or "Additional governed prerequisites still remain."
                )
        else:
            headline = str(
                result.get("headline", "Governed runtime preparation failed.")
            )
        return {
            "ok": bool(result.get("ok", False)),
            "headline": headline,
            "message": headline,
            "details": details,
            "state": self.current_frontend_state_snapshot(),
            "governed": governed_status,
        }

    def decide_reseed(
        self,
        *,
        operator_decision: str,
        operator_note: str = "",
        continue_after_approval: bool = False,
    ) -> dict[str, Any]:
        snapshot = self._observability_snapshot()
        workspace_root = str(snapshot.get("workspace_root", "")).strip()
        if not workspace_root:
            return {
                "ok": False,
                "headline": "No active workspace is available for reseed review.",
                "details": [
                    "Complete a bounded governed run before attempting review-based continuation.",
                ],
            }
        try:
            result = materialize_successor_reseed_decision(
                workspace_root=workspace_root,
                operator_decision=operator_decision,
                operator_note=operator_note,
                operator_root=self.operator_root,
            )
        except Exception as exc:
            return {
                "ok": False,
                "headline": "Reseed decision could not be recorded.",
                "details": [str(exc)],
            }

        decision_payload = dict(result.get("decision", {}))
        effective_payload = dict(result.get("effective_next_objective", {}))
        self.update_profile(resume_mode="resume_existing", launch_action="governed_execution")
        details = [
            f"Decision: {decision_payload.get('operator_decision', '')}",
            f"Reseed state: {decision_payload.get('reseed_state', '')}",
            f"Continuation authorized: {bool(effective_payload.get('continuation_authorized', False))}",
            f"Effective next objective id: {effective_payload.get('objective_id', '') or '<none>'}",
            f"Reseed request: {result.get('reseed_request_path', '')}",
            f"Reseed decision: {result.get('reseed_decision_path', '')}",
            f"Lineage: {result.get('continuation_lineage_path', '')}",
            f"Effective next objective: {result.get('effective_next_objective_path', '')}",
        ]
        notice = {
            "ok": True,
            "headline": "Reseed decision recorded.",
            "details": details,
        }
        if continue_after_approval and str(operator_decision).strip().lower() == "approve":
            launch_result = self.launch(
                resume_mode="resume_existing",
                launch_action="governed_execution",
                state_root=str(self.state_root),
            )
            launch_details = list(launch_result.get("details", []))
            notice["headline"] = "Reseed approved and governed continuation launched."
            notice["ok"] = bool(launch_result.get("ok", False))
            notice["details"] = details + launch_details
            if str(launch_result.get("summary", "")).strip():
                notice["summary"] = str(launch_result.get("summary", ""))
        return notice

    def decide_baseline_admission(
        self,
        *,
        operator_decision: str,
        operator_note: str = "",
    ) -> dict[str, Any]:
        snapshot = self._observability_snapshot()
        workspace_root = str(snapshot.get("workspace_root", "")).strip()
        if not workspace_root:
            return {
                "ok": False,
                "headline": "No active workspace is available for candidate admission review.",
                "details": [
                    "Complete a bounded promotion-bundle objective before attempting baseline admission review.",
                ],
            }
        try:
            result = materialize_successor_baseline_admission_decision(
                workspace_root=workspace_root,
                operator_decision=operator_decision,
                operator_note=operator_note,
            )
        except Exception as exc:
            return {
                "ok": False,
                "headline": "Baseline admission decision could not be recorded.",
                "details": [str(exc)],
            }

        decision_payload = dict(result.get("decision", {}))
        remediation_payload = dict(result.get("remediation_proposal", {}))
        admitted_candidate_payload = dict(result.get("admitted_candidate", {}))
        comparison_payload = dict(result.get("baseline_comparison", {}))
        reference_target_payload = dict(result.get("reference_target", {}))
        revised_candidate_bundle = dict(result.get("revised_candidate_bundle", {}))
        revised_candidate_comparison = dict(
            result.get("revised_candidate_comparison", {})
        )
        revised_candidate_promotion_summary = dict(
            result.get("revised_candidate_promotion_summary", {})
        )
        reference_target_consumption_payload = dict(
            result.get("reference_target_consumption", {})
        )
        next_objective_payload = dict(result.get("next_objective_proposal", {}))
        quality_roadmap_outputs = dict(result.get("quality_roadmap_outputs", {}))
        next_pack_plan = dict(quality_roadmap_outputs.get("next_pack_plan", {}))
        return {
            "ok": True,
            "headline": "Baseline admission decision recorded.",
            "details": [
                f"Decision: {decision_payload.get('operator_decision', '')}",
                f"Admission state: {decision_payload.get('admission_decision_state', '')}",
                "Admitted bounded baseline candidate: "
                + str(
                    bool(
                        decision_payload.get(
                            "admitted_bounded_baseline_candidate",
                            False,
                        )
                    )
                ),
                f"Recommendation state: {decision_payload.get('admission_recommendation_state', '')}",
                f"Remediation required: {bool(decision_payload.get('remediation_required', False))}",
                f"Admission review: {snapshot.get('baseline_admission_review_path', '') or '<none>'}",
                f"Admission decision: {result.get('decision_path', '')}",
                "Remediation proposal: "
                + str(
                    result.get("remediation_proposal_path", "")
                    or remediation_payload.get("objective_id", "")
                    or "<none>"
                ),
                "Admitted candidate state: "
                + str(admitted_candidate_payload.get("admitted_candidate_state", "") or "<none>"),
                "Baseline comparison: "
                + str(comparison_payload.get("comparison_result_state", "") or "<none>"),
                "Reference target: "
                + str(reference_target_payload.get("reference_target_state", "") or "<none>"),
                "Revised candidate state: "
                + str(revised_candidate_bundle.get("revised_candidate_state", "") or "<none>"),
                "Revised candidate id: "
                + str(revised_candidate_bundle.get("revised_candidate_id", "") or "<none>"),
                "Revised candidate stronger than prior admitted candidate in aggregate: "
                + str(
                    bool(
                        revised_candidate_comparison.get(
                            "materially_stronger_than_prior_admitted_candidate_in_aggregate",
                            False,
                        )
                    )
                ),
                "Reference target rollover: "
                + str(
                    revised_candidate_promotion_summary.get(
                        "reference_target_rollover_state",
                        "",
                    )
                    or "<none>"
                ),
                "Reference target consumption: "
                + str(
                    reference_target_consumption_payload.get("consumption_state", "")
                    or "<none>"
                ),
                "Next quality objective: "
                + str(next_objective_payload.get("objective_id", "") or "<none>"),
                "Next recommended skill pack: "
                + str(next_pack_plan.get("selected_skill_pack_id", "") or "<none>"),
            ],
        }

    def _delegation_context(self) -> dict[str, str]:
        snapshot = self.current_operator_snapshot()
        observability = self._observability_snapshot()
        current_session_summary = dict(snapshot.get("operator_current_session_summary", {}))
        workspace_root = self._remap_packaged_path(
            _first_non_empty_text(
                observability.get("workspace_root", ""),
                current_session_summary.get("workspace_root", ""),
                fallback="",
            )
        )
        workspace_id = _first_non_empty_text(
            observability.get("workspace_id", ""),
            current_session_summary.get("workspace_id", ""),
            fallback="",
        )
        directive_id = _first_non_empty_text(
            observability.get("directive_id", ""),
            current_session_summary.get("directive_id", ""),
            fallback="",
        )
        return {
            "workspace_root": workspace_root,
            "workspace_id": workspace_id,
            "directive_id": directive_id,
        }

    def _librarian_mission_context(
        self,
        *,
        directive_id: str,
        workspace_id: str,
        workspace_root: str,
    ) -> dict[str, Any]:
        workspace_root_text = str(workspace_root or "").strip()
        workspace_artifacts_root = (
            Path(workspace_root_text) / "artifacts" if workspace_root_text else None
        )
        trusted_source_artifact_ids: list[str] = []
        if workspace_artifacts_root and workspace_artifacts_root.exists():
            trusted_source_artifact_ids = sorted(
                path.stem
                for path in workspace_artifacts_root.glob("trusted_source_*latest.json")
            )
        invalidation_present = (
            "trusted_source_knowledge_invalidation_latest"
            in trusted_source_artifact_ids
        )
        supersession_present = (
            "trusted_source_knowledge_supersession_latest"
            in trusted_source_artifact_ids
        )
        mission_id = "successor_trusted_source_library_hygiene_support"
        mission_title = (
            "Strengthen trusted-source library hygiene support for bounded successor readiness review."
        )
        mission_target = (
            "Produce a Controller-reviewed knowledge/skill library maintenance bundle that clarifies trusted-source inventory and supersession hygiene for the active workspace."
        )
        local_handling_sufficient = bool(
            trusted_source_artifact_ids and invalidation_present and supersession_present
        )
        delegation_recommended = bool(
            trusted_source_artifact_ids and not local_handling_sufficient
        )
        if delegation_recommended:
            delegation_reason = (
                "The active workspace has trusted-source artifacts but its invalidation/supersession hygiene is not fully surfaced, so a bounded Librarian maintenance pass can strengthen successor-readiness review."
            )
        elif local_handling_sufficient:
            delegation_reason = (
                "The active workspace already exposes trusted-source invalidation and supersession hygiene, so the Controller can keep this library-readiness step local."
            )
        elif workspace_root_text:
            delegation_reason = (
                "The active workspace does not currently expose enough trusted-source library context to justify a delegated Librarian pass."
            )
        else:
            delegation_reason = (
                "No active workspace is attached to the current session, so a mission-integrated Librarian pass is not justified yet."
            )
        workspace_bundle_path = (
            str(workspace_artifacts_root / "controller_librarian_mission_bundle_latest.json")
            if workspace_artifacts_root
            else ""
        )
        workspace_improvement_path = (
            str(
                workspace_artifacts_root
                / "controller_librarian_mission_improvement_latest.json"
            )
            if workspace_artifacts_root
            else ""
        )
        return {
            "mission_id": mission_id,
            "mission_class": "trusted_source_library_hygiene",
            "mission_title": mission_title,
            "mission_target": mission_target,
            "directive_id": str(directive_id or "").strip(),
            "workspace_id": str(workspace_id or "").strip(),
            "workspace_root": workspace_root_text,
            "workspace_trusted_artifact_count": len(trusted_source_artifact_ids),
            "workspace_trusted_artifact_ids": trusted_source_artifact_ids,
            "invalidation_present": invalidation_present,
            "supersession_present": supersession_present,
            "local_handling_sufficient": local_handling_sufficient,
            "delegation_recommended": delegation_recommended,
            "delegation_reason": delegation_reason,
            "workspace_bundle_path": workspace_bundle_path,
            "workspace_improvement_path": workspace_improvement_path,
        }

    def _record_librarian_mission_state(
        self,
        *,
        mission_context: dict[str, Any],
        decision_state: str,
        decision_label: str,
        decision_reason: str,
        child_id: str,
        delegated: bool,
        review_required: bool,
        continuation_allowed: bool,
        adoption_state: str,
        mission_result_state: str,
        mission_result_summary: str,
        mission_improved: bool,
        adopted_bundle_used: bool,
        child_artifact_paths: list[str] | None = None,
        operator_note: str = "",
        write_workspace_artifacts: bool = False,
    ) -> dict[str, str]:
        artifact_paths = [str(path) for path in list(child_artifact_paths or []) if str(path)]
        workspace_artifact_paths: list[str] = []
        workspace_bundle_path = str(mission_context.get("workspace_bundle_path", "") or "")
        workspace_improvement_path = str(
            mission_context.get("workspace_improvement_path", "") or ""
        )
        if write_workspace_artifacts and workspace_bundle_path and workspace_improvement_path:
            workspace_bundle_payload = {
                "schema_name": "ControllerLibrarianMissionBundle",
                "schema_version": "controller_librarian_mission_bundle_v1",
                "mission_id": str(mission_context.get("mission_id", "") or ""),
                "mission_class": str(mission_context.get("mission_class", "") or ""),
                "mission_title": str(mission_context.get("mission_title", "") or ""),
                "directive_id": str(mission_context.get("directive_id", "") or ""),
                "workspace_id": str(mission_context.get("workspace_id", "") or ""),
                "workspace_root": str(mission_context.get("workspace_root", "") or ""),
                "decision_state": decision_state,
                "decision_label": decision_label,
                "mission_result_state": mission_result_state,
                "mission_result_summary": mission_result_summary,
                "delegated": bool(delegated),
                "review_required": bool(review_required),
                "continuation_allowed": bool(continuation_allowed),
                "adopted_bundle_used": bool(adopted_bundle_used),
                "artifact_paths": artifact_paths,
            }
            workspace_improvement_payload = {
                "schema_name": "ControllerLibrarianMissionImprovementWorkspace",
                "schema_version": "controller_librarian_mission_improvement_workspace_v1",
                "mission_id": str(mission_context.get("mission_id", "") or ""),
                "mission_class": str(mission_context.get("mission_class", "") or ""),
                "mission_state": mission_result_state,
                "mission_improved": bool(mission_improved),
                "delegated": bool(delegated),
                "adopted_bundle_used": bool(adopted_bundle_used),
                "trusted_source_artifact_count": int(
                    mission_context.get("workspace_trusted_artifact_count", 0) or 0
                ),
                "invalidation_present": bool(
                    mission_context.get("invalidation_present", False)
                ),
                "supersession_present": bool(
                    mission_context.get("supersession_present", False)
                ),
                "improvement_summary": mission_result_summary,
                "artifact_paths": artifact_paths,
            }
            _write_json_file(workspace_bundle_path, workspace_bundle_payload)
            _write_json_file(workspace_improvement_path, workspace_improvement_payload)
            workspace_artifact_paths = [workspace_bundle_path, workspace_improvement_path]

        save_controller_delegation_decision(
            {
                "schema_name": CONTROLLER_DELEGATION_DECISION_SCHEMA_NAME,
                "schema_version": CONTROLLER_DELEGATION_DECISION_SCHEMA_VERSION,
                "mission_id": str(mission_context.get("mission_id", "") or ""),
                "mission_class": str(mission_context.get("mission_class", "") or ""),
                "mission_title": str(mission_context.get("mission_title", "") or ""),
                "mission_target": str(mission_context.get("mission_target", "") or ""),
                "directive_id": str(mission_context.get("directive_id", "") or ""),
                "workspace_id": str(mission_context.get("workspace_id", "") or ""),
                "workspace_root": str(mission_context.get("workspace_root", "") or ""),
                "decision_state": decision_state,
                "decision_label": decision_label,
                "decision_reason": decision_reason,
                "child_role": "librarian",
                "child_id": str(child_id or ""),
                "delegated": bool(delegated),
                "review_required": bool(review_required),
                "continuation_allowed": bool(continuation_allowed),
                "delegation_recommended": bool(
                    mission_context.get("delegation_recommended", False)
                ),
                "local_handling_sufficient": bool(
                    mission_context.get("local_handling_sufficient", False)
                ),
                "workspace_trusted_artifact_count": int(
                    mission_context.get("workspace_trusted_artifact_count", 0) or 0
                ),
                "workspace_trusted_artifact_ids": list(
                    mission_context.get("workspace_trusted_artifact_ids", [])
                ),
                "operator_note": str(operator_note or "").strip(),
                "artifact_paths": [*artifact_paths, *workspace_artifact_paths],
            },
            root=self.operator_root,
        )
        save_controller_child_adoption_summary(
            {
                "schema_name": CONTROLLER_CHILD_ADOPTION_SUMMARY_SCHEMA_NAME,
                "schema_version": CONTROLLER_CHILD_ADOPTION_SUMMARY_SCHEMA_VERSION,
                "mission_id": str(mission_context.get("mission_id", "") or ""),
                "mission_class": str(mission_context.get("mission_class", "") or ""),
                "adoption_state": adoption_state,
                "decision_label": decision_label,
                "child_role": "librarian",
                "child_id": str(child_id or ""),
                "review_required": bool(review_required),
                "continuation_allowed": bool(continuation_allowed),
                "mission_improved": bool(mission_improved),
                "adopted_bundle_used": bool(adopted_bundle_used),
                "mission_result_state": mission_result_state,
                "mission_result_summary": mission_result_summary,
                "artifact_paths": [*artifact_paths, *workspace_artifact_paths],
                "operator_note": str(operator_note or "").strip(),
            },
            root=self.operator_root,
        )
        save_controller_librarian_mission_improvement(
            {
                "schema_name": CONTROLLER_LIBRARIAN_MISSION_IMPROVEMENT_SCHEMA_NAME,
                "schema_version": CONTROLLER_LIBRARIAN_MISSION_IMPROVEMENT_SCHEMA_VERSION,
                "mission_id": str(mission_context.get("mission_id", "") or ""),
                "mission_class": str(mission_context.get("mission_class", "") or ""),
                "mission_title": str(mission_context.get("mission_title", "") or ""),
                "directive_id": str(mission_context.get("directive_id", "") or ""),
                "workspace_id": str(mission_context.get("workspace_id", "") or ""),
                "workspace_root": str(mission_context.get("workspace_root", "") or ""),
                "mission_state": mission_result_state,
                "mission_improved": bool(mission_improved),
                "delegated": bool(delegated),
                "adopted_bundle_used": bool(adopted_bundle_used),
                "trusted_source_artifact_count": int(
                    mission_context.get("workspace_trusted_artifact_count", 0) or 0
                ),
                "invalidation_present": bool(
                    mission_context.get("invalidation_present", False)
                ),
                "supersession_present": bool(
                    mission_context.get("supersession_present", False)
                ),
                "decision_state": decision_state,
                "decision_label": decision_label,
                "decision_reason": decision_reason,
                "improvement_summary": mission_result_summary,
                "artifact_paths": [*artifact_paths, *workspace_artifact_paths],
            },
            root=self.operator_root,
        )
        return {
            "workspace_bundle_path": workspace_bundle_path if workspace_artifact_paths else "",
            "workspace_improvement_path": (
                workspace_improvement_path if workspace_artifact_paths else ""
            ),
        }

    def _verifier_mission_context(
        self,
        *,
        directive_id: str,
        workspace_id: str,
        workspace_root: str,
        target_context: dict[str, Any],
    ) -> dict[str, Any]:
        workspace_root_text = str(workspace_root or "").strip()
        workspace_artifacts_root = (
            Path(workspace_root_text) / "artifacts" if workspace_root_text else None
        )
        target_role = str(target_context.get("verification_target_role", "") or "").strip()
        target_role_label = str(
            target_context.get("verification_target_role_label", "")
            or _child_role_label(target_role)
        ).strip()
        target_bundle_path = str(
            target_context.get("verification_target_bundle_path", "") or ""
        ).strip()
        target_artifact_paths = [
            str(item).strip()
            for item in list(target_context.get("verification_target_artifact_paths", []) or [])
            if str(item).strip()
        ]
        verification_target_available = bool(
            target_context.get("verification_target_available", False)
        )
        mission_id = "successor_bundle_adoption_readiness_support"
        mission_title = (
            "Strengthen bounded bundle adoption readiness before Controller use."
        )
        mission_target = (
            f"Inspect the pending {target_role_label} bundle for contract completeness, provenance coverage, and adoption readiness before any explicit Controller adoption."
            if verification_target_available
            else "Keep adoption-readiness handling local when no separate Verifier pass is justified for the current bounded mission output."
        )
        local_handling_sufficient = not verification_target_available
        delegation_recommended = verification_target_available
        delegation_reason = str(
            target_context.get("delegation_reason", "") or ""
        ).strip()
        workspace_bundle_path = (
            str(workspace_artifacts_root / "controller_verifier_mission_bundle_latest.json")
            if workspace_artifacts_root
            else ""
        )
        workspace_improvement_path = (
            str(
                workspace_artifacts_root
                / "controller_verifier_mission_improvement_latest.json"
            )
            if workspace_artifacts_root
            else ""
        )
        return {
            "mission_id": mission_id,
            "mission_class": "bundle_adoption_readiness",
            "mission_title": mission_title,
            "mission_target": mission_target,
            "directive_id": str(directive_id or "").strip(),
            "workspace_id": str(workspace_id or "").strip(),
            "workspace_root": workspace_root_text,
            "verification_target_available": verification_target_available,
            "verification_target_kind": str(
                target_context.get("verification_target_kind", "") or ""
            ),
            "verification_target_role": target_role,
            "verification_target_role_label": target_role_label,
            "verification_target_child_id": str(
                target_context.get("verification_target_child_id", "") or ""
            ).strip(),
            "verification_target_bundle_path": target_bundle_path,
            "verification_target_artifact_paths": target_artifact_paths,
            "local_handling_sufficient": local_handling_sufficient,
            "delegation_recommended": delegation_recommended,
            "delegation_reason": delegation_reason,
            "workspace_bundle_path": workspace_bundle_path,
            "workspace_improvement_path": workspace_improvement_path,
        }

