            {_render_story_card("Lease / termination", controller_resource_lease_payload.get("lease_state", "") or "<none>", detail=str(child_termination_summary_payload.get("termination_state", "") or "<none>"), tone="info")}
            {_render_story_card("Delegation path", controller_mission_delegation_plan_payload.get("chosen_path_label", "") or "<none>", detail=str(controller_mission_delegation_plan_payload.get("chosen_path_reason", "") or "<none>"), tone="info")}
            {_render_story_card("Blocked options", int(controller_blocked_delegation_options_payload.get("blocked_option_count", 0) or 0), detail=str(controller_blocked_delegation_options_payload.get("selected_path_label", "") or "<none>"), tone="warning" if int(controller_blocked_delegation_options_payload.get("blocked_option_count", 0) or 0) else "success")}
            {_render_story_card("Typed handoff", controller_typed_handoff_contract_payload.get("handoff_state_label", "") or controller_typed_handoff_contract_payload.get("handoff_state", "") or "<none>", detail=str(controller_typed_handoff_contract_payload.get("handoff_summary", "") or "<none>"), tone="info")}
